"use client";

import { renderFrame, type FrameSource } from "@mcut/compositor";
import { createAssetFromFile, getActiveMediaItems, type PreviewMediaPool } from "@mcut/media";
import type { AssetRef, EditorEngine } from "@mcut/timeline";
import { ensureProjectFontsLoaded } from "./font-library";
import { saveAssetBlob } from "./persistence";

export interface ViewportStill {
  asset: AssetRef;
  file: File;
  width: number;
  height: number;
}

export interface CaptureViewportStillOptions {
  scale?: number;
  source?: FrameSource | PreviewMediaPool;
}

function slugPart(value: string): string {
  return (
    value
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "") || "mcut"
  );
}

function timePart(timeMs: number): string {
  const totalSeconds = Math.max(0, Math.floor(timeMs / 1000));
  const ms = Math.max(0, Math.round(timeMs % 1000));
  const seconds = totalSeconds % 60;
  const minutes = Math.floor(totalSeconds / 60) % 60;
  const hours = Math.floor(totalSeconds / 3600);
  return `${hours.toString().padStart(2, "0")}-${minutes
    .toString()
    .padStart(2, "0")}-${seconds.toString().padStart(2, "0")}-${ms.toString().padStart(3, "0")}`;
}

async function canvasToPngFile(canvas: HTMLCanvasElement, filename: string): Promise<File> {
  const blob = await new Promise<Blob | null>((resolve) => canvas.toBlob(resolve, "image/png"));
  if (!blob) throw new Error("Could not encode PNG");
  return new File([blob], filename, { type: "image/png" });
}

/**
 * Render the current playhead frame into a PNG, register it as a normal image
 * asset, and persist the blob so it survives reload with the rest of the bin.
 */
export async function captureViewportStill(
  engine: EditorEngine,
  options: CaptureViewportStillOptions = {},
): Promise<ViewportStill> {
  const project = engine.project;
  const timeMs = engine.playback.state.currentTimeMs;
  const scale = Math.max(1, Math.min(4, Math.round(options.scale ?? 1)));
  const width = Math.max(1, Math.round(project.width * scale));
  const height = Math.max(1, Math.round(project.height * scale));
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext("2d");
  if (!ctx) throw new Error("Could not create capture canvas");

  const source = options.source;
  if (source && "sync" in source) {
    source.sync(getActiveMediaItems(project, timeMs), {
      isPlaying: false,
      playbackRate: engine.playback.state.playbackRate,
      masterVolume: engine.playback.state.volume,
      muted: true,
    });
  }

  await ensureProjectFontsLoaded(project);
  ctx.setTransform(scale, 0, 0, scale, 0, 0);
  renderFrame(ctx, project, timeMs, { source });

  const suffix = scale === 1 ? "" : `-${scale}x`;
  const file = await canvasToPngFile(
    canvas,
    `${slugPart(project.name)}-${timePart(timeMs)}${suffix}.png`,
  );
  const asset = await createAssetFromFile(file);
  engine.dispatch({ type: "addAsset", asset }, { history: false });
  await saveAssetBlob(asset, file);
  return { asset, file, width, height };
}

"use client";

import { ChevronRightIcon, XIcon } from "@/lib/hugeicons";
import { useEditor, usePlayback } from "@mcut/react";
import {
  getKeyframes,
  getStaticValue,
  hasKeyframes,
  isOnKeyframe,
  type AnimatableProperty,
  type Easing,
  type TimelineElement,
} from "@mcut/timeline";
import { cn } from "@/lib/utils";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

export const EASING_PRESETS: Array<{ label: string; value: Easing }> = [
  { label: "Linear", value: "linear" },
  { label: "Ease in", value: "easeIn" },
  { label: "Ease out", value: "easeOut" },
  { label: "Ease in-out", value: "easeInOut" },
  { label: "Hold", value: "hold" },
];

/** Element-local playhead, clamped into the clip. */
export function localPlayheadMs(element: TimelineElement, timelineMs: number): number {
  return Math.max(0, Math.min(element.durationMs, Math.round(timelineMs - element.startMs)));
}

/** A CapCut-style keyframe diamond (rotated square). */
export function Diamond({
  filled,
  armed,
  className,
}: {
  filled: boolean;
  armed?: boolean;
  className?: string;
}) {
  return (
    <span
      className={cn(
        "inline-block size-2 rotate-45 border transition-colors",
        filled
          ? "border-primary bg-primary"
          : armed
            ? "border-primary bg-transparent"
            : "border-muted-foreground/70 bg-transparent",
        className,
      )}
    />
  );
}

/**
 * Premiere's Effect-Controls keyframe cluster for one property:
 * ◀ (previous) ◆ (toggle at playhead; first tap arms the stopwatch)
 * ▶ (next), an easing menu when sitting on a keyframe, and a stopwatch-off
 * (clear) affordance when armed.
 */
export function KeyframeRowControls({
  element,
  property,
}: {
  element: TimelineElement;
  property: AnimatableProperty;
}) {
  const engine = useEditor();
  const armed = hasKeyframes(element, property);
  const playheadMs = usePlayback((s) => Math.round(s.currentTimeMs));
  const localMs = localPlayheadMs(element, playheadMs);
  const track = getKeyframes(element, property);
  const onKeyframe = armed && isOnKeyframe(element, property, playheadMs);
  const previous = [...track].reverse().find((k) => k.timeMs < localMs);
  const next = track.find((k) => k.timeMs > localMs);
  const currentKeyframe = track.find((k) => Math.abs(k.timeMs - localMs) <= 1);

  const toggle = () => {
    try {
      if (onKeyframe) {
        if (track.length === 1) {
          // Removing the last keyframe = stopwatch off; keep the current value.
          const value = currentKeyframe?.value;
          engine.transact(() => {
            engine.dispatch({ type: "clearKeyframes", elementId: element.id, property });
            if (value !== undefined) applyStatic(value);
          });
        } else {
          engine.dispatch({
            type: "removeKeyframe",
            elementId: element.id,
            property,
            timeMs: currentKeyframe!.timeMs,
          });
        }
      } else {
        const value = armed
          ? // Adding between keyframes: freeze the interpolated value.
            undefined
          : getStaticValue(element, property);
        engine.dispatch({
          type: "setKeyframe",
          elementId: element.id,
          property,
          timeMs: localMs,
          value: value ?? interpolatedNow(),
        });
      }
    } catch {
      // Element vanished or invalid time: ignore.
    }
  };

  const interpolatedNow = () => {
    // getAnimatedValue without importing it twice — track is non-empty here.
    const before = [...track].reverse().find((k) => k.timeMs <= localMs);
    const after = track.find((k) => k.timeMs >= localMs);
    if (!before) return after!.value;
    if (!after || after === before) return before.value;
    const t = (localMs - before.timeMs) / (after.timeMs - before.timeMs);
    return before.value + (after.value - before.value) * t;
  };

  const applyStatic = (value: number) => {
    const patch: Record<string, unknown> = {};
    if (property === "opacity") patch.opacity = Math.min(1, Math.max(0, value));
    else if (property === "volume") patch.volume = Math.min(2, Math.max(0, value));
    // Animated blur has no static counterpart on the element — its resting
    // value is 0 and persistent blur lives in the effects stack instead.
    else if (property === "blur") return;
    else if (property === "letterSpacing") {
      if (element.type !== "text") return;
      patch.style = { ...element.style, letterSpacing: value };
    }
    else if ("transform" in element) {
      const key = { "position.x": "x", "position.y": "y", "scale.x": "scaleX", "scale.y": "scaleY", rotation: "rotation" }[property];
      patch.transform = { ...element.transform, [key as string]: value };
    }
    engine.dispatch({ type: "updateElement", elementId: element.id, patch });
  };

  const seekTo = (timeMs: number) => engine.seek(element.startMs + timeMs);

  const disarm = () => {
    if (!window.confirm(`Delete all ${track.length} ${property} keyframe(s)?`)) return;
    engine.dispatch({ type: "clearKeyframes", elementId: element.id, property });
  };

  return (
    <span className="group/kf flex shrink-0 items-center gap-px">
      <button
        type="button"
        className="flex size-4 items-center justify-center text-muted-foreground hover:text-foreground disabled:opacity-25"
        disabled={!previous}
        title="Previous keyframe"
        onClick={() => previous && seekTo(previous.timeMs)}
      >
        <ChevronRightIcon className="size-3 rotate-180" />
      </button>
      <button
        type="button"
        className="flex size-4 items-center justify-center"
        title={
          onKeyframe
            ? "Remove keyframe at playhead"
            : armed
              ? "Add keyframe at playhead"
              : "Arm keyframes (stopwatch on) — adds one at the playhead"
        }
        onClick={toggle}
      >
        <Diamond filled={onKeyframe} armed={armed} />
      </button>
      <button
        type="button"
        className="flex size-4 items-center justify-center text-muted-foreground hover:text-foreground disabled:opacity-25"
        disabled={!next}
        title="Next keyframe"
        onClick={() => next && seekTo(next.timeMs)}
      >
        <ChevronRightIcon className="size-3" />
      </button>
      {armed && onKeyframe && currentKeyframe && (
        <DropdownMenu>
          <DropdownMenuTrigger
            render={
              <button
                type="button"
                className="flex h-4 items-center px-0.5 font-mono text-2xs text-muted-foreground hover:text-foreground"
                title="Interpolation toward the next keyframe"
              />
            }
          >
            ∿
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuLabel>Interpolation</DropdownMenuLabel>
            <DropdownMenuItem
              onClick={() => {
                window.dispatchEvent(
                  new CustomEvent("mcut:open-curve-editor", {
                    detail: { elementId: element.id, property },
                  }),
                );
              }}
            >
              Curve editor…
              <span className="ml-auto pl-3 font-mono text-2xs text-muted-foreground">∿</span>
            </DropdownMenuItem>
            {EASING_PRESETS.map((preset) => (
              <DropdownMenuItem
                key={preset.label}
                onClick={() =>
                  engine.dispatch({
                    type: "setKeyframeEasing",
                    elementId: element.id,
                    property,
                    timeMs: currentKeyframe.timeMs,
                    easing: preset.value,
                  })
                }
              >
                {preset.label}
                {(currentKeyframe.easing ?? "linear") === preset.value && (
                  <span className="ml-auto pl-3 text-primary">•</span>
                )}
              </DropdownMenuItem>
            ))}
          </DropdownMenuContent>
        </DropdownMenu>
      )}
      {armed && (
        <button
          type="button"
          className="flex size-4 items-center justify-center text-muted-foreground opacity-0 transition-opacity group-hover/kf:opacity-100 hover:text-destructive"
          title="Stopwatch off — delete all keyframes for this property"
          onClick={disarm}
        >
          <XIcon className="size-2.5" />
        </button>
      )}
    </span>
  );
}

"use client";

import { useEffect, useRef, type PointerEvent as ReactPointerEvent } from "react";
import { useEditor, useProject } from "@mcut/react";
import {
  getEffectiveVolume,
  getKeyframes,
  hasKeyframes,
  animatableProperties,
  type TimelineElement,
} from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { useEditorUI } from "./editor-ui";
import { collectSnapTargets, snapTime } from "./timeline-snap";

const SNAP_PX = 8;

/** Unique, sorted element-local keyframe times across every armed property. */
function aggregatedTimes(element: TimelineElement): number[] {
  const times = new Set<number>();
  for (const property of animatableProperties(element)) {
    for (const keyframe of getKeyframes(element, property)) times.add(keyframe.timeMs);
  }
  return [...times].sort((a, b) => a - b);
}

/**
 * CapCut-style keyframe diamonds on a selected clip. Drag retimes (snapping
 * to clip edges and the playhead), click seeks to the keyframe, Alt-click
 * deletes it across all properties.
 */
export function KeyframeMarkers({
  element,
  pxPerMs,
}: {
  element: TimelineElement;
  pxPerMs: number;
}) {
  const engine = useEditor();
  const project = useProject();
  const { snapEnabled, setSnapGuideMs } = useEditorUI();
  const dragRef = useRef<{ timeMs: number; startClientX: number; moved: boolean } | null>(null);

  const removeAt = (timeMs: number) => {
    engine.transact(() => {
      for (const property of animatableProperties(element)) {
        if (getKeyframes(element, property).some((k) => k.timeMs === timeMs)) {
          try {
            engine.dispatch({ type: "removeKeyframe", elementId: element.id, property, timeMs });
          } catch {
            // Already gone.
          }
        }
      }
    });
  };

  const onPointerDown = (timeMs: number) => (event: ReactPointerEvent<HTMLButtonElement>) => {
    event.stopPropagation();
    if (event.altKey) {
      removeAt(timeMs);
      return;
    }
    dragRef.current = { timeMs, startClientX: event.clientX, moved: false };
    engine.beginTransaction();
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const onPointerMove = (event: ReactPointerEvent<HTMLButtonElement>) => {
    const drag = dragRef.current;
    if (!drag) return;
    const deltaMs = (event.clientX - drag.startClientX) / pxPerMs;
    if (!drag.moved && Math.abs(deltaMs * pxPerMs) < 3) return;
    drag.moved = true;

    let desiredLocal = Math.round(drag.timeMs + deltaMs);
    desiredLocal = Math.max(0, Math.min(element.durationMs, desiredLocal));
    const snapped = snapTime(
      element.startMs + desiredLocal,
      collectSnapTargets(engine.project, engine.playback.state.currentTimeMs, new Set([element.id])),
      SNAP_PX / pxPerMs,
      { enabled: snapEnabled && !event.altKey },
    );
    const toTimeMs = Math.max(0, Math.min(element.durationMs, snapped.ms - element.startMs));
    if (toTimeMs === drag.timeMs) return;

    const live = engine.project.tracks.flatMap((t) => t.elements).find((e) => e.id === element.id);
    if (!live) return;
    for (const property of animatableProperties(live)) {
      if (getKeyframes(live, property).some((k) => k.timeMs === drag.timeMs)) {
        try {
          engine.dispatch({
            type: "moveKeyframe",
            elementId: element.id,
            property,
            fromTimeMs: drag.timeMs,
            toTimeMs,
          });
        } catch {
          // Collision on this property: leave it.
        }
      }
    }
    drag.timeMs = toTimeMs;
    drag.startClientX = event.clientX;
    setSnapGuideMs(snapped.guideMs);
  };

  const onPointerUp = (event: ReactPointerEvent<HTMLButtonElement>) => {
    const drag = dragRef.current;
    if (!drag) return;
    dragRef.current = null;
    engine.endTransaction();
    setSnapGuideMs(null);
    event.currentTarget.releasePointerCapture(event.pointerId);
    if (!drag.moved) engine.seek(element.startMs + drag.timeMs);
  };

  void project; // markers re-render with project changes via parent

  return (
    <>
      {aggregatedTimes(element).map((timeMs) => (
        <button
          key={timeMs}
          type="button"
          className="absolute bottom-0 z-30 flex h-3.5 w-3 -translate-x-1/2 cursor-ew-resize items-center justify-center"
          style={{ left: timeMs * pxPerMs }}
          title="Keyframe — drag to retime, click to seek, ⌥-click to delete"
          onPointerDown={onPointerDown(timeMs)}
          onPointerMove={onPointerMove}
          onPointerUp={onPointerUp}
          onPointerCancel={onPointerUp}
        >
          <span className="size-1.5 rotate-45 border border-overlay/60 bg-overlay-foreground shadow-sm" />
        </button>
      ))}
    </>
  );
}

/**
 * Premiere-style volume rubber band on audio clips: the line shows the
 * resolved volume curve; drag vertically to set volume (the nearest keyframe
 * when armed), ⌘/Ctrl-click to add a keyframe on the band.
 */
export function VolumeBand({
  element,
  widthPx,
  heightPx,
  interactive,
}: {
  element: TimelineElement & { type: "audio" | "video" };
  widthPx: number;
  heightPx: number;
  interactive: boolean;
}) {
  const engine = useEditor();
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const dragRef = useRef<{ targetTimeMs: number | null } | null>(null);
  const armed = hasKeyframes(element, "volume");

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const width = Math.max(1, Math.round(widthPx));
    const height = Math.max(1, Math.round(heightPx));
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    ctx.strokeStyle = "rgba(103, 232, 249, 0.95)";
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    for (let x = 0; x <= width; x += 3) {
      const timelineMs = element.startMs + (x / width) * element.durationMs;
      // Effective volume (keyframes × fades): the band shows what plays.
      const volume = Math.max(0, Math.min(2, getEffectiveVolume(element, timelineMs)));
      const y = height - (volume / 2) * height;
      if (x === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    }
    ctx.stroke();
  }, [element, widthPx, heightPx]);

  const valueFromY = (event: ReactPointerEvent<HTMLDivElement>): number => {
    const rect = event.currentTarget.getBoundingClientRect();
    const ratio = 1 - (event.clientY - rect.top) / rect.height;
    return Math.round(Math.max(0, Math.min(2, ratio * 2)) * 100) / 100;
  };

  const localTimeFromX = (event: ReactPointerEvent<HTMLDivElement>): number => {
    const rect = event.currentTarget.getBoundingClientRect();
    const ratio = (event.clientX - rect.left) / rect.width;
    return Math.max(0, Math.min(element.durationMs, Math.round(ratio * element.durationMs)));
  };

  const onPointerDown = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!interactive) return;
    event.stopPropagation();
    engine.beginTransaction();
    if (event.metaKey || event.ctrlKey) {
      // ⌘-click: add a keyframe on the band (arms the property).
      const timeMs = localTimeFromX(event);
      try {
        engine.dispatch({
          type: "setKeyframe",
          elementId: element.id,
          property: "volume",
          timeMs,
          value: valueFromY(event),
        });
      } catch {
        // Element vanished.
      }
      dragRef.current = { targetTimeMs: timeMs };
    } else if (armed) {
      // Drag the nearest keyframe's value (time stays put).
      const timeMs = localTimeFromX(event);
      const track = getKeyframes(element, "volume");
      const nearest = track.reduce((best, k) =>
        Math.abs(k.timeMs - timeMs) < Math.abs(best.timeMs - timeMs) ? k : best,
      );
      dragRef.current = { targetTimeMs: nearest.timeMs };
    } else {
      dragRef.current = { targetTimeMs: null }; // static volume drag
    }
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const onPointerMove = (event: ReactPointerEvent<HTMLDivElement>) => {
    const drag = dragRef.current;
    if (!drag) return;
    const value = valueFromY(event);
    try {
      if (drag.targetTimeMs === null) {
        engine.dispatch({ type: "updateElement", elementId: element.id, patch: { volume: value } });
      } else {
        engine.dispatch({
          type: "setKeyframe",
          elementId: element.id,
          property: "volume",
          timeMs: drag.targetTimeMs,
          value,
        });
      }
    } catch {
      // Ignore mid-drag races.
    }
  };

  const onPointerUp = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!dragRef.current) return;
    dragRef.current = null;
    engine.endTransaction();
    event.currentTarget.releasePointerCapture(event.pointerId);
  };

  return (
    <div
      className={cn(
        "absolute inset-0 z-20",
        interactive ? "cursor-ns-resize" : "pointer-events-none",
      )}
      title={
        interactive
          ? "Volume band — drag to set, ⌘-click to add a keyframe"
          : undefined
      }
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={onPointerUp}
      onPointerCancel={onPointerUp}
    >
      <canvas ref={canvasRef} className="pointer-events-none absolute inset-0 size-full" />
    </div>
  );
}

"use client";

import { toast } from "sonner";
import { SparklesIcon } from "@/lib/hugeicons";
