function prettyName(preset: AnimationPreset): string {
  return preset.replace(/-/g, " ");
}

/**
 * Saved zooms: built-ins plus the user's captured presets. Click applies at
 * the playhead (relative to the clip's current framing); Save captures the
 * selected clip's scale/position keyframes as a reusable preset.
 */
function ZoomsSection() {
  const engine = useEditor();
  const selected = useSelectedElement();
  const playheadMs = usePlayback((s) => s.currentTimeMs);
  const userZooms = useTemplates<ZoomPreset>("zoom");
  const element = selected?.element;
  const zoomable =
    element &&
    (element.type === "video" ||
      element.type === "image" ||
      element.type === "text" ||
      element.type === "multicam");

  const apply = (preset: ZoomPreset) => {
    if (!element || !zoomable) return;
    const atMs = Math.round(
      Math.max(0, Math.min(playheadMs - element.startMs, element.durationMs - preset.durationMs)),
    );
    try {
      engine.dispatch({ type: "applyZoomPreset", elementId: element.id, preset, atMs });
      toast.success(`${preset.name} applied at the playhead`);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Could not apply the zoom");
    }
  };

  const save = () => {
    if (!element) return;
    const name = window.prompt("Name this zoom", "My zoom");
    if (!name) return;
    const preset = captureZoomPreset(element, name);
    if (!preset) {
      toast.error("Add scale/position keyframes first, then save them as a zoom.");
      return;
    }
    saveTemplate("zoom", name, preset);
    toast.success(`Saved "${name}" — it now applies to any clip in one click`);
  };

  const zooms: Array<{ preset: ZoomPreset; templateId?: string }> = [
    ...ZOOM_PRESETS.map((preset) => ({ preset })),
    ...userZooms.map((t) => ({ preset: t.payload, templateId: t.id })),
  ];

  return (
    <div className="flex flex-col gap-1.5">
      <div className="flex items-center px-1">
        <PanelSectionLabel className="flex-1">Zooms</PanelSectionLabel>
        <Button variant="ghost" size="xs" disabled={!element} onClick={save} title="Capture the selected clip's scale/position keyframes as a reusable zoom">
          Save zoom
        </Button>
      </div>
      <div className="grid grid-cols-2 gap-1.5">
        {zooms.map(({ preset, templateId }, i) => (
          <button
            key={templateId ?? `builtin-${i}`}
            type="button"
            disabled={!zoomable}
            className="group/zoom relative flex aspect-[2/1] flex-col items-center justify-center gap-0.5 rounded-lg bg-foreground/[0.05] transition-colors hover:bg-primary/10 disabled:opacity-50"
            onClick={() => apply(preset)}
            title={`${preset.name} · ${(preset.durationMs / 1000).toFixed(2)}s — applies at the playhead`}
          >
            <ZoomSparkline preset={preset} />
            <span className="text-2xs">{preset.name}</span>
            {templateId && (
              <span
                role="button"
                tabIndex={-1}
                className="absolute top-0.5 right-1 hidden text-2xs text-muted-foreground group-hover/zoom:block hover:text-destructive"
                title="Delete saved zoom"
                onClick={(event) => {
                  event.stopPropagation();
                  removeTemplate(templateId);
                }}
              >
                ✕
              </span>
            )}
          </button>
        ))}
      </div>
    </div>
  );
}

/** Tiny scale-over-time curve preview. */
function ZoomSparkline({ preset }: { preset: ZoomPreset }) {
  const track = preset.tracks["scale.x"] ?? preset.tracks["scale.y"];
  if (!track) return <span className="text-lg leading-none text-primary">⊕</span>;
  const values = track.map((k) => k.value);
  const min = Math.min(...values, 1);
  const max = Math.max(...values, 1);
  const span = Math.max(0.0001, max - min);
  const points = track
    .map((k) => `${(k.t * 44 + 2).toFixed(1)},${(14 - ((k.value - min) / span) * 12 + 1).toFixed(1)}`)
    .join(" ");
  return (
    <svg width="48" height="16" viewBox="0 0 48 16" className="text-primary">
      <polyline points={points} fill="none" stroke="currentColor" strokeWidth="1.5" />
    </svg>
  );
}

/**
 * CapCut-style In / Out / Emphasis animation gallery. Presets EXPAND into
 * ordinary keyframes on the selected element — open the inspector afterwards
 * and every diamond is there to edit.
 */
export function AnimationsPanel({ className }: { className?: string }) {
  const engine = useEditor();
  const selected = useSelectedElement();
  const element = selected?.element;
  const animatable = element ? animatableProperties(element).length > 0 : false;

  const apply = (preset: AnimationPreset) => {
    if (!element) return;
    try {
      engine.dispatch({ type: "applyAnimationPreset", elementId: element.id, preset });
      toast.success(`${prettyName(preset)} applied — keyframes are editable in the inspector`);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Could not apply the preset");
    }
  };

  if (!element || !animatable) {
    return (
      <EmptyState
        className={className}
        icon={SparklesIcon}
        description={
          element
            ? "This element has no animatable properties."
            : "Select a clip to apply an animation. Presets expand into editable keyframes."
        }
      />
    );
  }

  return (
    <div className={cn("flex flex-col gap-3 p-2", className)}>
      <ZoomsSection />
      {(Object.keys(ANIMATION_PRESET_CATEGORIES) as Array<keyof typeof ANIMATION_PRESET_CATEGORIES>).map(
        (category) => (
          <div key={category} className="flex flex-col gap-1.5">
            <PanelSectionLabel className="px-1">{CATEGORY_LABELS[category]}</PanelSectionLabel>
            <div className="grid grid-cols-2 gap-1.5">
              {ANIMATION_PRESET_CATEGORIES[category].map((preset) => (
                <button
                  key={preset}
                  type="button"
                  data-preset={preset}
                  className="flex aspect-[2/1] flex-col items-center justify-center gap-1 rounded-lg border bg-overlay/40 transition-colors hover:border-primary/60 hover:bg-primary/10"
                  onClick={() => apply(preset)}
                  title={`${PRESET_HINTS[preset]} — expands to editable keyframes`}
                >
                  <span className="text-lg leading-none text-primary">{PRESET_GLYPHS[preset]}</span>
                  <span className="text-2xs capitalize">{prettyName(preset)}</span>
                </button>
              ))}
            </div>
          </div>
        ),
      )}
      <p className="px-1 text-2xs leading-relaxed text-muted-foreground">
        Presets write real keyframes — fine-tune them with the ◆ controls in the inspector.
      </p>
    </div>
  );
}

"use client";

import {
  useEffect,
  useRef,
  useState,
  type PointerEvent as ReactPointerEvent,
} from "react";
import { SortableContext, verticalListSortingStrategy } from "@dnd-kit/sortable";
import {
  ImageIcon,
  MaximizeIcon,
  PlusIcon,
  ZoomInIcon,
  ZoomOutIcon,
} from "@/lib/hugeicons";
import { useEditor, useEditorState, usePlayback, useProject } from "@mcut/react";
import {
  getProjectDurationMs,
  rangesOverlap,
  type ElementId,
} from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { useActiveDrag } from "./editor-dnd";
import { PanelHeader } from "./editor-primitives";
import {
  MAX_PX_PER_MS,
  MIN_PX_PER_MS,
  useEditorUI,
} from "./editor-ui";
import { formatTimecode } from "./format";
import {
  ClipDragProvider,
  NEW_TRACK_LANE_HEIGHT,
  RULER_HEIGHT,
  TRACK_HEIGHT,
  useClipDragController,
} from "./timeline-drag";
import { MarkerLines, Playhead, Ruler, SnapGuide } from "./timeline-ruler";
import { DropGhostOverlay, HEADER_WIDTH, NewTrackLane, SortableRow } from "./timeline-tracks";

// ---------------------------------------------------------------------------
// Marquee selection
// ---------------------------------------------------------------------------

interface MarqueeState {
  x0: number;
  y0: number;
  x1: number;
  y1: number;
  active: boolean;
}

// ---------------------------------------------------------------------------
// Panel
// ---------------------------------------------------------------------------

export interface TimelinePanelProps {
  className?: string;
}

/**
 * Multi-track NLE timeline: magnetic clip move/trim with guide lines,
 * filmstrip/waveform clips, option-drag duplication to new tracks, dnd-kit
 * drop target lanes with ghost preview, marquee + shift multi-select,
 * sortable tracks, ⌘+wheel zoom at pointer.
 */
export function TimelinePanel({ className }: TimelinePanelProps) {
  const engine = useEditor();
  const project = useProject();
  const activeDrag = useActiveDrag();
  const clipDrag = useClipDragController();
  const { pxPerMs, setPxPerMs, zoomBy, timelineScrollRef, setMode } = useEditorUI();
  const durationMs = useEditorState((s) => getProjectDurationMs(s.project));
  const [marquee, setMarquee] = useState<MarqueeState | null>(null);
  const contentRef = useRef<HTMLDivElement | null>(null);

  // Quantized: while a drag grows the project, a raw width would change on
  // every frame and defeat the lanes' memoization.
  const contentWidth = Math.max(1600, Math.ceil(((durationMs + 15_000) * pxPerMs) / 400) * 400);
  const mediaDragActive = activeDrag !== null && activeDrag.kind !== "track";
  const rows = [...project.tracks].map((track, index) => ({ track, index })).reverse();
  const totalHeight = RULER_HEIGHT + NEW_TRACK_LANE_HEIGHT + rows.length * TRACK_HEIGHT;

  // ⌘/ctrl+wheel zoom anchored at the pointer (non-passive listener).
  useEffect(() => {
    const scroller = timelineScrollRef.current;
    if (!scroller) return;
    const onWheel = (event: WheelEvent) => {
      if (!event.ctrlKey && !event.metaKey) return;
      event.preventDefault();
      const rect = scroller.getBoundingClientRect();
      const anchorMs =
        (scroller.scrollLeft + (event.clientX - rect.left) - HEADER_WIDTH) / pxPerMs;
      zoomBy(event.deltaY < 0 ? 1.12 : 1 / 1.12, Math.max(0, anchorMs));
    };
    scroller.addEventListener("wheel", onWheel, { passive: false });
    return () => scroller.removeEventListener("wheel", onWheel);
  }, [pxPerMs, zoomBy, timelineScrollRef]);

  const fitToView = () => {
    const scroller = timelineScrollRef.current;
    if (!scroller || durationMs === 0) return;
    setPxPerMs((scroller.clientWidth - HEADER_WIDTH - 60) / durationMs);
    scroller.scrollLeft = 0;
  };

  // -- marquee ---------------------------------------------------------------

  const toContentPoint = (event: ReactPointerEvent) => {
    const rect = contentRef.current!.getBoundingClientRect();
    return { x: event.clientX - rect.left, y: event.clientY - rect.top };
  };

  const onBackgroundPointerDown = (event: ReactPointerEvent<HTMLDivElement>) => {
    const target = event.target as HTMLElement;
    if (!target.dataset.mcutLane) return; // clips/headers handle their own
    const point = toContentPoint(event);
    setMarquee({ x0: point.x, y0: point.y, x1: point.x, y1: point.y, active: false });
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const onBackgroundPointerMove = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!marquee) return;
    const point = toContentPoint(event);
    const next = { ...marquee, x1: point.x, y1: point.y };
    next.active =
      next.active || Math.hypot(next.x1 - next.x0, next.y1 - next.y0) > 5;
    setMarquee(next);
    if (!next.active) return;

    // Select clips intersecting the marquee (time × visual rows).
    const fromMs = (Math.min(next.x0, next.x1) - HEADER_WIDTH) / pxPerMs;
    const toMs = (Math.max(next.x0, next.x1) - HEADER_WIDTH) / pxPerMs;
    const rowsTop = RULER_HEIGHT + NEW_TRACK_LANE_HEIGHT;
    const rowTop = Math.floor((Math.min(next.y0, next.y1) - rowsTop) / TRACK_HEIGHT);
    const rowBottom = Math.floor((Math.max(next.y0, next.y1) - rowsTop) / TRACK_HEIGHT);
    const ids: ElementId[] = [];
    rows.forEach(({ track }, visualRow) => {
      if (visualRow < rowTop || visualRow > rowBottom) return;
      for (const element of track.elements) {
        if (rangesOverlap(fromMs, Math.max(1, toMs - fromMs), element.startMs, element.durationMs)) {
          ids.push(element.id);
        }
      }
    });
    engine.select(ids);
  };

  const onBackgroundPointerUp = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!marquee) return;
    if (!marquee.active) {
      // Plain click on empty lane: seek there and clear selection.
      engine.seek(Math.max(0, (marquee.x0 - HEADER_WIDTH) / pxPerMs));
      engine.clearSelection();
    }
    setMarquee(null);
    event.currentTarget.releasePointerCapture(event.pointerId);
  };

  const zoomSliderValue = Math.log(pxPerMs / MIN_PX_PER_MS) / Math.log(MAX_PX_PER_MS / MIN_PX_PER_MS);

  return (
    <ClipDragProvider value={clipDrag}>
    <div className={cn("flex flex-col", className)} data-mcut-timeline="">
      <PanelHeader>
        <Button
          variant="ghost"
          size="xs"
          title="Add track"
          onClick={() => engine.dispatch({ type: "addTrack" })}
        >
          <PlusIcon /> Track
        </Button>
        <Button
          variant="ghost"
          size="xs"
          title="Edit the cover (first 5 frames)"
          onClick={() => {
            setMode("thumbnail");
            engine.seek(0);
          }}
        >
          <ImageIcon /> Cover
        </Button>
        <div className="flex-1" />
        <Button variant="ghost" size="icon-xs" title="Fit timeline" onClick={fitToView}>
          <MaximizeIcon />
        </Button>
        <Button variant="ghost" size="icon-xs" title="Zoom out" onClick={() => zoomBy(1 / 1.4)}>
          <ZoomOutIcon />
        </Button>
        <Slider
          value={zoomSliderValue * 100}
          min={0}
          max={100}
          step={1}
          className="w-28! shrink-0"
          onValueChange={(value) => {
            const v = (Array.isArray(value) ? (value[0] ?? 0) : value) / 100;
            setPxPerMs(MIN_PX_PER_MS * Math.pow(MAX_PX_PER_MS / MIN_PX_PER_MS, v));
          }}
        />
        <Button variant="ghost" size="icon-xs" title="Zoom in" onClick={() => zoomBy(1.4)}>
          <ZoomInIcon />
        </Button>
      </PanelHeader>

      <div
        ref={timelineScrollRef}
        // isolate: the sticky ruler/gutter z-indexes (60/70) must not compete
        // with portaled popups (context menus are z-50 at the body level).
        className="relative isolate min-h-0 flex-1 overflow-auto overscroll-contain"
      >
        <div
          ref={contentRef}
          className="relative w-max min-w-full"
          style={{ minHeight: totalHeight }}
          onPointerDown={onBackgroundPointerDown}
          onPointerMove={onBackgroundPointerMove}
          onPointerUp={onBackgroundPointerUp}
        >
          {/* Ruler row */}
          <div className="sticky top-0 z-[60] flex">
            <div
              className="sticky left-0 z-[70] flex shrink-0 items-center justify-center border-r border-foreground/10 bg-card"
              style={{ width: HEADER_WIDTH, height: RULER_HEIGHT }}
            >
              <CurrentTime />
            </div>
            <Ruler pxPerMs={pxPerMs} contentWidth={contentWidth} />
          </div>

          <NewTrackLane contentWidth={contentWidth} dragActive={mediaDragActive} />

          <SortableContext
            items={rows.map(({ track }) => track.id)}
            strategy={verticalListSortingStrategy}
          >
            {rows.map(({ track }) => (
              <SortableRow
                key={track.id}
                track={track}
                pxPerMs={pxPerMs}
                contentWidth={contentWidth}
              />
            ))}
          </SortableContext>

          {durationMs === 0 && !activeDrag && (
            <div
              className="pointer-events-none absolute inset-x-0 top-1/2 z-0 flex justify-center text-xs text-muted-foreground"
              style={{ paddingLeft: HEADER_WIDTH }}
            >
              Drag media here, or press the import button in the media bin
            </div>
          )}

          {marquee?.active && (
            <div
              className="pointer-events-none absolute z-40 border border-primary bg-primary/10"
              style={{
                left: Math.min(marquee.x0, marquee.x1),
                top: Math.min(marquee.y0, marquee.y1),
                width: Math.abs(marquee.x1 - marquee.x0),
                height: Math.abs(marquee.y1 - marquee.y0),
              }}
            />
          )}

          <DropGhostOverlay rows={rows} pxPerMs={pxPerMs} />
          <MarkerLines pxPerMs={pxPerMs} height={totalHeight} />
          <SnapGuide pxPerMs={pxPerMs} height={totalHeight} />
          <Playhead pxPerMs={pxPerMs} height={totalHeight} />
        </div>
      </div>
    </div>
    </ClipDragProvider>
  );
}

