/**
 * The inspector: collapsible sections with scrubbable fields (drag a label
 * to adjust), sliders, and a full color picker — for the selected element,
 * or project settings when nothing is selected.
 */
export function PropertiesPanel({ className }: { className?: string }) {
  const engine = useEditor();
  const project = useProject();
  const selected = useSelectedElement();
  const { editingLayoutId, mode, setEditingTextId } = useEditorUI();
  // Re-render with the playhead only while the selection is keyframed, so the
  // inspector shows live resolved values (Premiere behavior) at no cost
  // for static elements.
  const anyArmed = selected ? hasKeyframes(selected.element) : false;
  const playheadMs = usePlayback((s) => (anyArmed ? Math.round(s.currentTimeMs) : -1));

  // Slot edit state takes over the inspector: while a layout is being edited
  // on the canvas, the panel styles its slots instead of the selection.
  const editingLayout = editingLayoutId
    ? project.layouts.find((l) => l.id === editingLayoutId)
    : undefined;
  if (editingLayout) return <LayoutSlotInspector layout={editingLayout} className={className} />;

  if (!selected) return <ProjectProperties />;
  const element = selected.element;
  const motionBlur = "motionBlur" in element ? element.motionBlur : undefined;
  const sizeHelpers = sizeHelpersForProject(project);
  const naturalSize = "transform" in element ? getElementNaturalSize(element, sizeHelpers) : null;
  const displaySize = "transform" in element ? getElementDisplaySize(element, sizeHelpers) : null;
  const timelineNowMs =
    playheadMs >= 0 ? playheadMs : Math.round(engine.playback.state.currentTimeMs);

  /** Resolved value for a row: keyframe track when armed, static otherwise. */
  const animValue = (property: AnimatableProperty, staticValue: number): number =>
    hasKeyframes(element, property)
      ? getAnimatedValue(element, property, timelineNowMs)
      : staticValue;

  /** Commit for a row: auto-key at the playhead when armed (stopwatch on). */
  const animCommit =
    (property: AnimatableProperty, staticCommit: (value: number) => void) =>
    (value: number) => {
      if (!hasKeyframes(element, property)) {
        staticCommit(value);
        return;
      }
      try {
        engine.dispatch({
          type: "setKeyframe",
          elementId: element.id,
          property,
          timeMs: localPlayheadMs(element, timelineNowMs),
          value,
        });
      } catch {
        // Element vanished mid-edit.
      }
    };

  const kfControls = (property: AnimatableProperty) => (
    <KeyframeRowControls element={element} property={property} />
  );

  const patch = (values: Record<string, unknown>, options?: { history?: boolean }) => {
    try {
      engine.dispatch({ type: "updateElement", elementId: element.id, patch: values }, options);
    } catch {
      // Invalid patch (overlap/bounds): drop it; inputs resync from state.
    }
  };
  const patchTransform = (
    values: Partial<{ x: number; y: number; scaleX: number; scaleY: number; rotation: number }>,
  ) => {
    if (!("transform" in element)) return;
    patch({ transform: { ...element.transform, ...values } });
  };
  const patchStyle = (values: Record<string, unknown>) => {
    if (element.type !== "text" && element.type !== "caption") return;
    patch({ style: { ...element.style, ...values } });
  };
  const patchDisplaySize = (values: Partial<{ width: number; height: number }>) => {
    if (!("transform" in element) || !naturalSize) return;
    if (element.type === "text") {
      const box: TextBox = {
        width: Math.max(
          1,
          Math.round((values.width ?? displaySize?.width ?? naturalSize.width) / element.transform.scaleX),
        ),
        overflow: element.box?.overflow ?? "clip",
        ...(values.height !== undefined || element.box?.height !== undefined
          ? {
              height: Math.max(
                1,
                Math.round((values.height ?? displaySize?.height ?? naturalSize.height) / element.transform.scaleY),
              ),
            }
          : {}),
      };
      patch({ box });
      return;
    }
    patch({
      transform: getTransformForDisplaySize(element.transform, naturalSize, {
        ...(values.width !== undefined ? { width: values.width } : {}),
        ...(values.height !== undefined ? { height: values.height } : {}),
      }),
    });
  };
  const trim = (values: Partial<{ startMs: number; durationMs: number; trimStartMs: number }>) => {
    try {
      engine.dispatch({ type: "trimElement", elementId: element.id, ...values });
    } catch {
      // Rejected (overlap/asset bounds): inputs resync from state.
    }
  };

  /**
   * The element's frame for the shared frame editor (the same FrameFields
   * the multicam slot inspector renders): its canvas-px bounding box,
   * translated to the center-origin transform on write. Armed properties
   * auto-key at the playhead, exactly like the bare rows did.
   */
  const frameTarget: FrameTarget | null = (() => {
    if (!("transform" in element) || !naturalSize || !displaySize) return null;
    const isText = element.type === "text";
    const width = isText
      ? displaySize.width
      : naturalSize.width * Math.abs(animValue("scale.x", element.transform.scaleX));
    const height = isText
      ? displaySize.height
      : naturalSize.height * Math.abs(animValue("scale.y", element.transform.scaleY));
    const W = project.width;
    const H = project.height;
    const safe = safeAreaRect(W, H);
    return {
      canvas: { width: W, height: H },
      safe: { x: safe.x * W, y: safe.y * H, width: safe.w * W, height: safe.h * H },
      rect: {
        x: W / 2 + animValue("position.x", element.transform.x) - width / 2,
        y: H / 2 + animValue("position.y", element.transform.y) - height / 2,
        width,
        height,
      },
      setRect: (patchRect: Partial<FrameRect>) => {
        const nextWidth = patchRect.width ?? width;
        const nextHeight = patchRect.height ?? height;
        // Static transform fields batch into ONE update (sequential patches
        // would each spread the stale render-time transform); armed
        // properties key individually and never touch the static transform.
        const staticPatch: Partial<{ x: number; y: number; scaleX: number; scaleY: number }> =
          {};
        const commit = (property: AnimatableProperty, value: number, write: () => void) =>
          animCommit(property, write)(value);
        if (isText) {
          // Text width/height size the layout box, not the scale.
          if (patchRect.width !== undefined || patchRect.height !== undefined) {
            patchDisplaySize({
              ...(patchRect.width !== undefined ? { width: Math.round(nextWidth) } : {}),
              ...(patchRect.height !== undefined ? { height: Math.round(nextHeight) } : {}),
            });
          }
        } else {
          if (patchRect.width !== undefined) {
            const scaleX =
              (element.transform.scaleX < 0 ? -1 : 1) *
              Math.max(0.001, nextWidth / naturalSize.width);
            commit("scale.x", scaleX, () => void (staticPatch.scaleX = scaleX));
          }
          if (patchRect.height !== undefined) {
            const scaleY =
              (element.transform.scaleY < 0 ? -1 : 1) *
              Math.max(0.001, nextHeight / naturalSize.height);
            commit("scale.y", scaleY, () => void (staticPatch.scaleY = scaleY));
          }
        }
        if (patchRect.x !== undefined) {
          const x = patchRect.x + nextWidth / 2 - W / 2;
          commit("position.x", x, () => void (staticPatch.x = x));
        }
        if (patchRect.y !== undefined) {
          const y = patchRect.y + nextHeight / 2 - H / 2;
          commit("position.y", y, () => void (staticPatch.y = y));
        }
        if (Object.keys(staticPatch).length > 0) patchTransform(staticPatch);
      },
      rotation: {
        value: animValue("rotation", element.transform.rotation),
        set: animCommit("rotation", (rotation) => patchTransform({ rotation })),
      },
      controls: (field) => {
        if (field === "x") return kfControls("position.x");
        if (field === "y") return kfControls("position.y");
        if (field === "rotation") return kfControls("rotation");
        // Text W/H edit the layout box, not scale — no scale keys there.
        if (isText) return undefined;
        return kfControls(field === "width" ? "scale.x" : "scale.y");
      },
    };
  })();

  return (
    <div className={cn("flex flex-col gap-1 p-3", className)}>
      <div className="flex items-center gap-2 pb-1">
        <span className="flex-1 truncate text-xs font-semibold capitalize">{element.type}</span>
        <Button
          variant="destructive"
          size="icon-xs"
          title="Delete element"
          onClick={() => engine.dispatch({ type: "removeElement", elementId: element.id })}
        >
          <Trash2Icon />
        </Button>
      </div>

      <Section title="Timing">
        <NumberField
          label="Start"
          value={element.startMs / 1000}
          step={0.1}
          min={0}
          unit="s"
          onCommit={(s) => trim({ startMs: Math.round(s * 1000) })}
        />
        <NumberField
          label="Duration"
          value={element.durationMs / 1000}
          step={0.1}
          min={0.01}
          unit="s"
          onCommit={(s) => {
            // Edge trim, not a raw window edit: the clip's remaining content
            // stays anchored (reversed spans and speed maps included).
            try {
              engine.dispatch({
                type: "trimEdge",
                elementId: element.id,
                edge: "end",
                deltaMs: Math.round(s * 1000) - element.durationMs,
              });
            } catch {
              // Rejected (bounds/overlap): inputs resync from state.
            }
          }}
        />
        {"trimStartMs" in element && (
          <NumberField
            label="Trim in"
            value={element.trimStartMs / 1000}
            step={0.1}
            min={0}
            unit="s"
            onCommit={(s) => trim({ trimStartMs: Math.round(s * 1000) })}
          />
        )}
        {(element.type === "video" || element.type === "audio") && (
          <NumberField
            label="Speed"
            value={Math.round(getAverageSpeed(element) * 100) * (element.reversed ? -1 : 1)}
            step={5}
            min={-2000}
            max={2000}
            unit="%"
            scrubPerPx={1}
            onCommit={(pct) => {
              // Signed percentage: 100 = normal, 50 = half speed, negative
              // plays backward (preview scrubs reversed clips, audio muted;
              // export renders them exactly).
              const reversed = pct < 0;
              const speed = Math.min(20, Math.max(0.05, Math.abs(pct) / 100));
              try {
                engine.transact(() => {
                  engine.dispatch({ type: "setElementSpeed", elementId: element.id, speed });
                  if (reversed !== (element.reversed ?? false)) {
                    engine.dispatch({
                      type: "updateElement",
                      elementId: element.id,
                      patch: { reversed: reversed || undefined },
                    });
                  }
                });
              } catch {
                // Rejected (overlap after rescale): inputs resync from state.
              }
            }}
          />
        )}
      </Section>

      {"transform" in element && (
        <Section
          title={frameTarget ? "Frame" : "Motion"}
          onReset={() => patch({ transform: { x: 0, y: 0, scaleX: 1, scaleY: 1, rotation: 0 } })}
        >
          {frameTarget ? (
            // Figma-basics frame rows, shared with the multicam slot editor.
            <FrameFields target={frameTarget} />
          ) : (
            // No natural size (multicam, unprobed media): offset semantics.
            <>
              <NumberField
                label="X"
                value={Math.round(animValue("position.x", element.transform.x) * 10) / 10}
                unit="px"
                scrubPerPx={1}
                onCommit={animCommit("position.x", (x) => patchTransform({ x }))}
                controls={kfControls("position.x")}
              />
              <NumberField
                label="Y"
                value={Math.round(animValue("position.y", element.transform.y) * 10) / 10}
                unit="px"
                scrubPerPx={1}
                onCommit={animCommit("position.y", (y) => patchTransform({ y }))}
                controls={kfControls("position.y")}
              />
              <NumberField
                label="Rotation"
                value={Math.round(animValue("rotation", element.transform.rotation) * 10) / 10}
                min={-180}
                max={180}
                unit="°"
                scrubPerPx={0.5}
                onCommit={animCommit("rotation", (rotation) => patchTransform({ rotation }))}
                controls={kfControls("rotation")}
              />
            </>
          )}
          <NumberField
            label="Scale"
            value={Math.round(animValue("scale.x", element.transform.scaleX) * 1000) / 1000}
            step={0.05}
            min={0.01}
            scrubPerPx={0.005}
            onCommit={(scale) => {
              // Uniform Scale: each axis keys independently when armed.
              animCommit("scale.x", () => patchTransform({ scaleX: scale, scaleY: scale }))(scale);
              if (hasKeyframes(element, "scale.y")) animCommit("scale.y", () => {})(scale);
            }}
            controls={kfControls("scale.x")}
          />
          <FieldRow label="Flip">
            <Button
              variant={element.transform.scaleX < 0 ? "secondary" : "outline"}
              size="xs"
              className="flex-1"
              title="Mirror horizontally"
              onClick={() => patchTransform({ scaleX: -element.transform.scaleX })}
            >
              Flip H
            </Button>
            <Button
              variant={element.transform.scaleY < 0 ? "secondary" : "outline"}
              size="xs"
              className="flex-1"
              title="Mirror vertically"
              onClick={() => patchTransform({ scaleY: -element.transform.scaleY })}
            >
              Flip V
            </Button>
          </FieldRow>
          <FieldRow
            label="Motion blur"
            title="Blur keyframed position/scale/rotation motion across a shutter window (AE layer model)"
          >
            <Switch
              checked={motionBlur?.enabled ?? false}
              onCheckedChange={(on) =>
                engine.dispatch({
                  type: "setMotionBlur",
                  elementId: element.id,
                  motionBlur: on
                    ? { enabled: true, shutterAngle: motionBlur?.shutterAngle ?? 180 }
                    : null,
                })
              }
            />
          </FieldRow>
          {motionBlur?.enabled && (
            <NumberField
              label="Shutter"
              value={motionBlur.shutterAngle}
              min={15}
              max={720}
              unit="°"
              scrubPerPx={2}
              onCommit={(shutterAngle) =>
                engine.dispatch({
                  type: "setMotionBlur",
                  elementId: element.id,
                  motionBlur: { enabled: true, shutterAngle },
                })
              }
            />
          )}
        </Section>
      )}

      {(element.type === "video" || element.type === "image") && (
        <Section
          title="Style"
          onReset={() =>
            patch({ cornerRadius: undefined, stroke: undefined, shadow: undefined })
          }
          actions={
            <PresetMenu
              kind="style"
              getValues={() => ({
                cornerRadius: element.cornerRadius ?? 0,
                stroke: element.stroke ?? null,
                shadow: element.shadow ?? null,
              })}
              onApply={(values) => {
                // Tolerant apply: a slot's boolean shadow becomes the
                // default element shadow; `fit` (slot-only) is ignored.
                const preset = readStylePreset(values);
                const patchValues: Record<string, unknown> = {};
                if (preset.cornerRadius !== undefined) patchValues.cornerRadius = preset.cornerRadius;
                if (preset.stroke !== undefined) patchValues.stroke = preset.stroke ?? undefined;
                if (preset.shadow !== undefined) {
                  patchValues.shadow =
                    preset.shadow === true
                      ? { ...DEFAULT_SHADOW }
                      : preset.shadow === false || preset.shadow === null
                        ? undefined
                        : preset.shadow;
                }
                patch(patchValues);
              }}
            />
          }
        >
          <RadiusRow
            value={element.cornerRadius ?? 0}
            onCommit={(cornerRadius) => patch({ cornerRadius: cornerRadius || undefined })}
          />
          <StrokeFields
            value={element.stroke}
            onCommit={(stroke) => patch({ stroke })}
          />
          <ShadowFields value={element.shadow} onCommit={(shadow) => patch({ shadow })} />
        </Section>
      )}

      {(element.type === "video" || element.type === "image") &&
        (() => {
          const asset = project.assets[element.assetId];
          if (!asset?.width || !asset?.height) return null;
          const srcW = asset.width;
          const srcH = asset.height;
          const crop: Crop = element.crop ?? { x: 0, y: 0, w: 1, h: 1 };
          const round4 = (v: number) => Math.round(v * 10_000) / 10_000;
          const setCrop = (next: Crop) => {
            const w = Math.min(1, Math.max(0.01, next.w));
            const h = Math.min(1, Math.max(0.01, next.h));
            const x = Math.min(Math.max(0, next.x), 1 - w);
            const y = Math.min(Math.max(0, next.y), 1 - h);
            const full = x === 0 && y === 0 && w === 1 && h === 1;
            patch({
              crop: full ? undefined : { x: round4(x), y: round4(y), w: round4(w), h: round4(h) },
            });
          };
          // Largest centered crop of the source with this frame aspect.
          const cropToAspect = (ratio: number) => {
            let w = 1;
            let h = srcW / ratio / srcH;
            if (h > 1) {
              w = (ratio * srcH) / srcW;
              h = 1;
            }
            setCrop({ x: (1 - w) / 2, y: (1 - h) / 2, w, h });
          };
          return (
            <Section
              title="Crop"
              defaultOpen={element.crop !== undefined}
              onReset={() => patch({ crop: undefined })}
            >
              <NumberField
                label="Left"
                value={Math.round(crop.x * srcW)}
                min={0}
                unit="px"
                scrubPerPx={2}
                onCommit={(px) => setCrop({ ...crop, x: px / srcW })}
              />
              <NumberField
                label="Top"
                value={Math.round(crop.y * srcH)}
                min={0}
                unit="px"
                scrubPerPx={2}
                onCommit={(px) => setCrop({ ...crop, y: px / srcH })}
              />
              <NumberField
                label="Width"
                value={Math.round(crop.w * srcW)}
                min={16}
                max={srcW}
                unit="px"
                scrubPerPx={2}
                onCommit={(px) => setCrop({ ...crop, w: px / srcW })}
              />
              <NumberField
                label="Height"
                value={Math.round(crop.h * srcH)}
                min={16}
                max={srcH}
                unit="px"
                scrubPerPx={2}
                onCommit={(px) => setCrop({ ...crop, h: px / srcH })}
              />
              <FieldRow label="Aspect" title="Largest centered crop with this shape">
                <div className="flex flex-1 gap-1">
                  {SLOT_ASPECTS.map(([label, ratio]) => (
                    <Button
                      key={label}
                      size="xs"
                      variant="outline"
                      className="flex-1"
                      onClick={() => cropToAspect(ratio)}
                    >
                      {label}
                    </Button>
                  ))}
                </div>
              </FieldRow>
              <p className="text-2xs text-muted-foreground">
                The kept region becomes the clip&apos;s frame on the canvas.
              </p>
            </Section>
          );
        })()}

      {"opacity" in element && (
        <Section title="Opacity">
          <NumberField
            label="Opacity"
            value={Math.round(animValue("opacity", element.opacity) * 100)}
            min={0}
            max={100}
            unit="%"
            scrubPerPx={0.5}
            onCommit={(pct) => animCommit("opacity", (opacity) => patch({ opacity }))(pct / 100)}
            controls={kfControls("opacity")}
          />
        </Section>
      )}

      {(element.type === "video" || element.type === "audio") && (
        <Section title="Audio">
          <NumberField
            label="Volume"
            value={Math.round(animValue("volume", element.volume) * 100)}
            min={0}
            max={200}
            unit="%"
            scrubPerPx={0.5}
            onCommit={(pct) => animCommit("volume", (volume) => patch({ volume }))(pct / 100)}
            controls={kfControls("volume")}
          />
          <NumberField
            label="Fade in"
            value={(element.fadeInMs ?? 0) / 1000}
            step={0.1}
            min={0}
            max={element.durationMs / 1000}
            unit="s"
            onCommit={(s) => patch({ fadeInMs: Math.round(s * 1000) })}
          />
          <NumberField
            label="Fade out"
            value={(element.fadeOutMs ?? 0) / 1000}
            step={0.1}
            min={0}
            max={element.durationMs / 1000}
            unit="s"
            onCommit={(s) => patch({ fadeOutMs: Math.round(s * 1000) })}
          />
          <div className="flex items-center gap-2">
            <span className="w-16 shrink-0 text-xs text-muted-foreground">Muted</span>
            <Switch checked={element.muted} onCheckedChange={(muted) => patch({ muted })} />
          </div>
        </Section>
      )}

      {element.type === "multicam" && mode === "multicam" && (
        <MulticamSection element={element} />
      )}

      {(element.type === "video" ||
        element.type === "image" ||
        element.type === "text" ||
        element.type === "multicam") && (
        <>
          <EffectsSection element={element} />
          <TransitionSection element={element} track={selected.track} />
        </>
      )}

      {element.type === "text" && (
        <Section
          title="Text"
          actions={
            <PresetMenu
              kind="text-style"
              getValues={() => ({ ...element.style })}
              onApply={(values) => patchStyle(values)}
            />
          }
        >
          {/* Content edits INLINE on the canvas (double-click), with
              per-range bold/italic/color via the selection toolbar. */}
          <Button
            variant="outline"
            size="xs"
            onClick={() => setEditingTextId(element.id)}
          >
            Edit text on canvas
          </Button>
          <p className="text-2xs text-muted-foreground">
            Or double-click the text in the preview. Select a range there to
            bold, italicize, or recolor just those words.
          </p>
          <TextStyleSection
            style={element.style}
            patchStyle={patchStyle}
            spacing={{
              value: Math.round(animValue("letterSpacing", element.style.letterSpacing ?? 0) * 10) / 10,
              onCommit: animCommit("letterSpacing", (letterSpacing) => patchStyle({ letterSpacing })),
              controls: kfControls("letterSpacing"),
            }}
          />
        </Section>
      )}

      {element.type === "caption" && (
        <Section title="Caption">
          <Textarea
            value={element.text}
            rows={3}
            className="text-xs"
            onChange={(e) => patch({ text: e.target.value, words: [] })}
          />
          <ChoiceRow
            label="Position"
            value={element.style.position}
            options={["top", "middle", "bottom"] as const}
            onCommit={(position) => patchStyle({ position })}
          />
          <div className="flex items-center gap-2">
            <span className="w-16 shrink-0 text-xs text-muted-foreground">Font</span>
            <FontPicker
              value={element.style.fontFamily}
              weight={element.style.fontWeight}
              onSelect={(fontFamily) => patchStyle({ fontFamily })}
              className="flex-1"
            />
          </div>
          <NumberField
            label="Size"
            value={element.style.fontSize}
            min={4}
            unit="px"
            onCommit={(fontSize) => patchStyle({ fontSize })}
          />
          <ColorField
            label="Color"
            value={element.style.color}
            onCommit={(color) => patchStyle({ color })}
          />
          <ColorField
            label="Fill"
            value={element.style.backgroundColor}
            onCommit={(backgroundColor) => patchStyle({ backgroundColor })}
          />
        </Section>
      )}
    </div>
  );
}

"use client";

import { useId, useRef, useState, type PointerEvent as ReactPointerEvent } from "react";
import { ChevronRightIcon, Undo2Icon } from "@/lib/hugeicons";
import { useEditor } from "@mcut/react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Input } from "@/components/ui/input";
import { InputGroup, InputGroupAddon, InputGroupInput } from "@/components/ui/input-group";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Slider } from "@/components/ui/slider";
import { panelSectionLabelClass } from "./editor-primitives";
import { clamp } from "./math";
import {
  ColorPicker,
  ColorPickerAlpha,
  ColorPickerEyeDropper,
  ColorPickerHue,
  ColorPickerOutput,
  ColorPickerSelection,
} from "@/components/kibo-ui/color-picker";

/**
 * The inspector's field vocabulary, shared by every editing surface (element
 * properties, multicam layout slots, project settings) so the same controls —
 * and muscle memory — apply everywhere. One row = a w-16 label + the control;
 * `Section` groups rows under a collapsible header.
 */

/** Label + control row; the layout primitive every field builds on. */
export function FieldRow({
  label,
  title,
  children,
}: {
  label: React.ReactNode;
  title?: string;
  children: React.ReactNode;
}) {
  return (
    <div className="flex items-center gap-2">
      <span className="w-16 shrink-0 text-xs text-muted-foreground" title={title}>
        {label}
      </span>
      {children}
    </div>
  );
}

/** The ONE input look for inspector fields (and the spinner-free numeric variant). */
export const inspectorInputClass = "h-full font-mono text-xs";
const numericInputClass = cn(
  inspectorInputClass,
  "[appearance:textfield] [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none",
);

/**
 * THE inspector number input, Figma-style: drag anywhere on the field (or
 * its label) to scrub the value horizontally — one undo entry per scrub — and
 * a clean click (or Tab) drops into text editing; commit on blur/Enter.
 */
export function NumberField({
  label,
  value,
  onCommit,
  step = 1,
  min,
  max,
  unit,
  scrubPerPx,
  controls,
  className,
}: {
  /** Row label; omit for compact embeds (the input still scrubs). */
  label?: string;
  value: number;
  onCommit: (value: number) => void;
  step?: number;
  min?: number;
  max?: number;
  unit?: string;
  /** Value change per pointer px while scrubbing. Default `step/2`. */
  scrubPerPx?: number;
  /** Trailing row controls (keyframe navigator). */
  controls?: React.ReactNode;
  className?: string;
}) {
  const engine = useEditor();
  const id = useId();
  const [text, setText] = useState(String(value));
  const [scrubbing, setScrubbing] = useState(false);
  const [editing, setEditing] = useState(false);
  const scrubRef = useRef<{ startX: number; base: number; moved: boolean } | null>(null);
  // Enter commits and blurs in one tick; the blur handler must not commit
  // AGAIN against the stale pre-dispatch `value` (that re-dispatch pushed a
  // no-op history entry, so the first undo afterwards appeared to do nothing).
  const skipBlurCommitRef = useRef(false);

  // Resync when the element changes underneath us (drag, undo, reselect).
  const [lastValue, setLastValue] = useState(value);
  if (value !== lastValue && !scrubbing && !editing) {
    setLastValue(value);
    setText(String(value));
  }

  const commitText = () => {
    const parsed = Number(text);
    if (!Number.isFinite(parsed)) {
      setText(String(value));
      return;
    }
    const next = clamp(parsed, min, max);
    if (next !== value) onCommit(next);
    setText(String(next));
  };

  const scrubDown = (event: ReactPointerEvent<HTMLElement>) => {
    scrubRef.current = { startX: event.clientX, base: value, moved: false };
    engine.beginTransaction();
    event.currentTarget.setPointerCapture(event.pointerId);
  };
  const scrubMove = (event: ReactPointerEvent<HTMLElement>) => {
    const scrub = scrubRef.current;
    if (!scrub) return;
    if (!scrub.moved) {
      if (Math.abs(event.clientX - scrub.startX) < 3) return;
      scrub.moved = true;
      setScrubbing(true);
    }
    const perPx = scrubPerPx ?? step / 2;
    const decimals = step < 1 ? 2 : 0;
    const raw = scrub.base + (event.clientX - scrub.startX) * perPx;
    const next = clamp(Number(raw.toFixed(decimals)), min, max);
    setText(String(next));
    onCommit(next);
  };
  /** Ends a scrub; returns true when the pointer never moved (a click). */
  const scrubUp = (event: ReactPointerEvent<HTMLElement>): boolean => {
    const scrub = scrubRef.current;
    if (!scrub) return false;
    scrubRef.current = null;
    engine.endTransaction();
    event.currentTarget.releasePointerCapture(event.pointerId);
    if (scrub.moved) {
      setScrubbing(false);
      setLastValue(NaN); // force resync from store on next render
      return false;
    }
    return true;
  };

  // The input surface scrubs too (Figma): preventDefault holds off focus;
  // a clean click then enters edit mode, dragging never does.
  const onInputPointerDown = (event: ReactPointerEvent<HTMLInputElement>) => {
    if (editing || event.button !== 0) return;
    event.preventDefault();
    scrubDown(event);
  };
  const onInputPointerUp = (event: ReactPointerEvent<HTMLInputElement>) => {
    if (editing) return;
    const input = event.currentTarget;
    if (scrubUp(event)) {
      input.focus();
      input.select();
    }
  };

  return (
    <div className={cn("flex items-center gap-2", className)}>
      {label !== undefined && (
        <label
          htmlFor={id}
          className="w-16 shrink-0 cursor-ew-resize text-xs text-muted-foreground select-none hover:text-primary"
          title="Drag to adjust"
          onPointerDown={scrubDown}
          onPointerMove={scrubMove}
          onPointerUp={scrubUp}
          onPointerCancel={scrubUp}
          // Label activation forwards focus into the input after EVERY scrub
          // — and editor shortcuts (incl. ⌘Z) are suppressed while an input
          // has focus, so undo went dead until the user clicked elsewhere
          // (usually losing their selection). Cancelling the click keeps the
          // label a pure scrub handle; clicking the input still edits.
          onClick={(event) => event.preventDefault()}
        >
          {label}
        </label>
      )}
      <InputGroup className="h-7 flex-1">
        <InputGroupInput
          id={id}
          type="number"
          step={step}
          value={text}
          onChange={(e) => setText(e.target.value)}
          onFocus={() => setEditing(true)}
          onBlur={() => {
            setEditing(false);
            if (skipBlurCommitRef.current) {
              skipBlurCommitRef.current = false;
              return;
            }
            commitText();
          }}
          onKeyDown={(e) => {
            if (e.key !== "Enter") return;
            commitText();
            // Commit-and-exit (Figma/Premiere): leaving edit mode returns
            // keyboard shortcuts to the editor right away.
            skipBlurCommitRef.current = true;
            e.currentTarget.blur();
          }}
          onPointerDown={onInputPointerDown}
          onPointerMove={(e) => !editing && scrubMove(e)}
          onPointerUp={onInputPointerUp}
          onPointerCancel={(e) => !editing && scrubUp(e)}
          className={cn(numericInputClass, !editing && "cursor-ew-resize select-none")}
        />
        {unit && (
          <InputGroupAddon align="inline-end" className="text-2xs text-muted-foreground">
            {unit}
          </InputGroupAddon>
        )}
      </InputGroup>
      {controls}
    </div>
  );
}

export function SliderField({
  label,
  value,
  onCommit,
  min = 0,
  max = 1,
  step = 0.01,
  display,
  controls,
}: {
  label: string;
  value: number;
  onCommit: (value: number) => void;
  min?: number;
  max?: number;
  step?: number;
  display?: string;
  controls?: React.ReactNode;
}) {
  return (
    <FieldRow label={label}>
      <Slider
        value={value}
        min={min}
        max={max}
        step={step}
        onValueChange={(v) => onCommit(Array.isArray(v) ? (v[0] ?? value) : v)}
        className="flex-1"
      />
      <span className="w-9 shrink-0 text-right font-mono text-2xs text-muted-foreground">
        {display ?? value.toFixed(2)}
      </span>
      {controls}
    </FieldRow>
  );
}

function toCssColor([r, g, b, a]: [number, number, number, number]): string {
  if (a >= 1) {
    const hex = (n: number) => Math.round(n).toString(16).padStart(2, "0");
    return `#${hex(r)}${hex(g)}${hex(b)}`;
  }
  return `rgba(${Math.round(r)}, ${Math.round(g)}, ${Math.round(b)}, ${Math.round(a * 100) / 100})`;
}

export function ColorField({
  label,
  value,
  onCommit,
}: {
  label: string;
  value: string;
  onCommit: (value: string) => void;
}) {
  const engine = useEditor();
  const [text, setText] = useState(value);
  const [editing, setEditing] = useState(false);
  // Resync the hex input when the element changes underneath us (undo, presets).
  const [lastValue, setLastValue] = useState(value);
  if (value !== lastValue && !editing) {
    setLastValue(value);
    setText(value);
  }

  // One undo entry per picker gesture: the picker commits on every pointer
  // move, which used to record a history entry per tick — undo then crawled
  // back through dozens of intermediate colors instead of reverting the drag.
  const beginPickerGesture = () => {
    engine.beginTransaction();
    const end = () => {
      window.removeEventListener("pointerup", end);
      window.removeEventListener("pointercancel", end);
      engine.endTransaction();
    };
    window.addEventListener("pointerup", end);
    window.addEventListener("pointercancel", end);
  };

  return (
    <FieldRow label={label}>
      <Popover>
        <PopoverTrigger
          render={
            <button
              type="button"
              aria-label={`${label} color`}
              className="size-7 shrink-0 rounded-md ring-1 ring-foreground/15"
              style={{ backgroundColor: value }}
            />
          }
        />
        <PopoverContent
          className="w-64 p-3"
          side="left"
          onPointerDownCapture={beginPickerGesture}
        >
          <ColorPicker
            className="flex flex-col gap-3"
            defaultValue={value}
            onChange={(rgba) => onCommit(toCssColor(rgba as [number, number, number, number]))}
          >
            <ColorPickerSelection className="h-28" />
            <div className="flex items-center gap-3">
              <ColorPickerEyeDropper />
              <div className="grid w-full gap-1.5">
                <ColorPickerHue />
                <ColorPickerAlpha />
              </div>
            </div>
            <ColorPickerOutput />
          </ColorPicker>
        </PopoverContent>
      </Popover>
      <Input
        value={text}
        onChange={(e) => setText(e.target.value)}
        onFocus={() => setEditing(true)}
        onBlur={() => {
          setEditing(false);
          // Commit once on exit, not per keystroke (each keystroke was a
          // history entry — and invalid intermediate colors like "#f").
          if (text !== value) onCommit(text);
        }}
        onKeyDown={(e) => e.key === "Enter" && e.currentTarget.blur()}
        className="h-7 flex-1 font-mono text-xs"
      />
    </FieldRow>
  );
}

export function Section({
  title,
  children,
  actions,
  onReset,
  defaultOpen = true,
}: {
  title: string;
  children: React.ReactNode;
  /** Header affordances (preset menu, …); shown on hover like reset. */
  actions?: React.ReactNode;
  onReset?: () => void;
  defaultOpen?: boolean;
}) {
  return (
    <Collapsible defaultOpen={defaultOpen} className="group/section">
      <div className="flex items-center">
        <CollapsibleTrigger
          render={
            <button
              type="button"
              className={cn(
                "flex flex-1 items-center gap-1 py-1 hover:text-foreground",
                panelSectionLabelClass,
              )}
            />
          }
        >
          <ChevronRightIcon className="size-3 transition-transform group-data-open/section:rotate-90" />
          {title}
        </CollapsibleTrigger>
        {actions}
        {onReset && (
          <Button
            variant="ghost"
            size="icon-xs"
            className="size-5 opacity-0 group-hover/section:opacity-100"
            title={`Reset ${title.toLowerCase()}`}
            onClick={onReset}
          >
            <Undo2Icon />
          </Button>
        )}
      </div>
      <CollapsibleContent className="flex flex-col gap-1.5 pt-1 pb-2">
        {children}
      </CollapsibleContent>
    </Collapsible>
  );
}

export function ChoiceRow<T extends string>({
  label,
  value,
  options,
  onCommit,
}: {
  label: string;
  value: T;
  options: readonly T[];
  onCommit: (value: T) => void;
}) {
  return (
    <FieldRow label={label}>
      <div className="flex flex-1 gap-1">
        {options.map((option) => (
          <Button
            key={option}
            size="xs"
            variant={option === value ? "secondary" : "ghost"}
            className={cn("flex-1 capitalize", option === value && "font-semibold")}
            onClick={() => onCommit(option)}
          >
            {option}
          </Button>
        ))}
      </div>
    </FieldRow>
  );
}

"use client";

import { DEFAULT_SHADOW, type Shadow, type Stroke } from "@mcut/timeline";
import { Switch } from "@/components/ui/switch";
import { ColorField, FieldRow, NumberField } from "./inspector-fields";

/**
 * Appearance rows for the shared style primitives (timeline style.ts) —
 * written ONCE and rendered by every surface that carries the primitive:
 * text glyphs, media frames (video/image), and multicam layout slots. Same
 * rows everywhere is what makes a "style" preset portable across them.
 */

/** Corner radius as a fraction of the short edge, shown as 0–50%. */
export function RadiusRow({
  value,
  onCommit,
}: {
  /** 0..0.5 */
  value: number;
  onCommit: (value: number) => void;
}) {
  return (
    <NumberField
      label="Radius"
      value={Math.round(value * 100)}
      min={0}
      max={50}
      unit="%"
      scrubPerPx={0.25}
      onCommit={(pct) => onCommit(pct / 100)}
    />
  );
}

/** Border/outline: width (0 removes) + color. */
export function StrokeFields({
  value,
  onCommit,
  label = "Border",
  defaultColor = "#ffffff",
  max = 200,
}: {
  value: Stroke | undefined;
  onCommit: (stroke: Stroke | undefined) => void;
  label?: string;
  defaultColor?: string;
  max?: number;
}) {
  return (
    <>
      <NumberField
        label={label}
        value={value?.width ?? 0}
        min={0}
        max={max}
        unit="px"
        scrubPerPx={0.25}
        onCommit={(width) =>
          onCommit(width > 0 ? { color: value?.color ?? defaultColor, width } : undefined)
        }
      />
      {value && (
        <ColorField
          label={label}
          value={value.color}
          onCommit={(color) => onCommit({ ...value, color })}
        />
      )}
    </>
  );
}

/** Drop shadow: switch + color/blur/offsets when on. */
export function ShadowFields({
  value,
  onCommit,
}: {
  value: Shadow | undefined;
  onCommit: (shadow: Shadow | undefined) => void;
}) {
  return (
    <>
      <FieldRow label="Shadow">
        <Switch
          checked={value !== undefined}
          onCheckedChange={(on) => onCommit(on ? { ...DEFAULT_SHADOW } : undefined)}
        />
      </FieldRow>
      {value && (
        <>
          <ColorField
            label="Shadow"
            value={value.color}
            onCommit={(color) => onCommit({ ...value, color })}
          />
          <NumberField
            label="Blur"
            value={value.blur}
            min={0}
            max={300}
            unit="px"
            scrubPerPx={0.5}
            onCommit={(blur) => onCommit({ ...value, blur })}
          />
          <NumberField
            label="Offset X"
            value={value.offsetX}
            min={-300}
            max={300}
            unit="px"
            scrubPerPx={0.5}
            onCommit={(offsetX) => onCommit({ ...value, offsetX })}
          />
          <NumberField
            label="Offset Y"
            value={value.offsetY}
            min={-300}
            max={300}
            unit="px"
            scrubPerPx={0.5}
            onCommit={(offsetY) => onCommit({ ...value, offsetY })}
          />
        </>
      )}
    </>
  );
}

/**
 * The "style" preset payload every surface saves/applies (tolerantly: each
 * surface keeps the keys it understands and ignores the rest, so a PiP look
 * saved on a slot lands on a clip and vice versa).
 */
export interface StylePresetValues {
  cornerRadius?: number;
  stroke?: Stroke | null;
  /** Elements store the full shadow; slots store a boolean. */
  shadow?: Shadow | boolean | null;
  fit?: "cover" | "contain";
}

export function readStylePreset(values: Record<string, unknown>): StylePresetValues {
  const out: StylePresetValues = {};
  if (typeof values.cornerRadius === "number") {
    out.cornerRadius = Math.min(0.5, Math.max(0, values.cornerRadius));
  }
  const stroke = values.stroke as { color?: unknown; width?: unknown } | null | undefined;
  if (stroke === null) out.stroke = null;
  else if (stroke && typeof stroke.color === "string" && typeof stroke.width === "number" && stroke.width > 0) {
    out.stroke = { color: stroke.color, width: stroke.width };
  }
  const shadow = values.shadow as
    | { color?: unknown; blur?: unknown; offsetX?: unknown; offsetY?: unknown }
    | boolean
    | null
    | undefined;
  if (shadow === null || typeof shadow === "boolean") out.shadow = shadow;
  else if (
    shadow &&
    typeof shadow.color === "string" &&
    typeof shadow.blur === "number" &&
    typeof shadow.offsetX === "number" &&
    typeof shadow.offsetY === "number"
  ) {
    out.shadow = {
      color: shadow.color,
      blur: shadow.blur,
      offsetX: shadow.offsetX,
      offsetY: shadow.offsetY,
    };
  }
  if (values.fit === "cover" || values.fit === "contain") out.fit = values.fit;
  return out;
}

"use client";

import { useState } from "react";
import {
  AlignBottomIcon,
  AlignCenterHorizontalIcon,
  AlignCenterVerticalIcon,
  AlignLeftIcon,
  AlignRightIcon,
  AlignTopIcon,
  LockIcon,
  LockOpenIcon,
} from "@/lib/hugeicons";
import { Button } from "@/components/ui/button";
import { FieldRow, NumberField } from "./inspector-fields";

/**
 * The Figma-basics frame editor — align, X/Y, W/H with an aspect lock, and
 * rotation — written once against {@link FrameTarget} so every surface that
 * can place a box on the canvas (timeline elements, multicam layout slots,
 * future overlays) gets the identical rows, gestures, and hotkeys instead of
 * a hand-rolled near-copy. Adapters translate the px-rect reads/writes into
 * whatever the surface stores (center-origin transforms, normalized rects).
 */

export interface FrameRect {
  x: number;
  y: number;
  width: number;
  height: number;
}

export type FrameField = "x" | "y" | "width" | "height" | "rotation";

export interface FrameTarget {
  /** Canvas size in px (the project frame). */
  canvas: { width: number; height: number };
  /** Safe-area rect in canvas px; edge alignments land here. */
  safe: FrameRect;
  /** Current frame in canvas px, top-left origin. */
  rect: FrameRect;
  /** Commit a partial frame change in canvas px. */
  setRect: (patch: Partial<FrameRect>) => void;
  /** Rotation in degrees, for surfaces that rotate. */
  rotation?: { value: number; set: (deg: number) => void };
  /** Smallest width/height the surface accepts (px). */
  minSize?: number;
  /** Trailing per-row controls (keyframe cluster for elements). */
  controls?: (field: FrameField) => React.ReactNode;
}

const ALIGNMENTS = [
  { key: "left", title: "Align left", Icon: AlignLeftIcon },
  { key: "center-h", title: "Align horizontal center", Icon: AlignCenterHorizontalIcon },
  { key: "right", title: "Align right", Icon: AlignRightIcon },
  { key: "top", title: "Align top", Icon: AlignTopIcon },
  { key: "center-v", title: "Align vertical center", Icon: AlignCenterVerticalIcon },
  { key: "bottom", title: "Align bottom", Icon: AlignBottomIcon },
] as const;

export type FrameAlignment = (typeof ALIGNMENTS)[number]["key"];

/** Where the rect lands for an alignment: safe-area edges, canvas centers. */
export function alignFrame(target: FrameTarget, alignment: FrameAlignment): Partial<FrameRect> {
  const { rect, safe, canvas } = target;
  switch (alignment) {
    case "left":
      return { x: safe.x };
    case "center-h":
      return { x: canvas.width / 2 - rect.width / 2 };
    case "right":
      return { x: safe.x + safe.width - rect.width };
    case "top":
      return { y: safe.y };
    case "center-v":
      return { y: canvas.height / 2 - rect.height / 2 };
    case "bottom":
      return { y: safe.y + safe.height - rect.height };
  }
}

/**
 * Frame rows for a {@link FrameTarget}. Renders bare rows (no Section
 * wrapper) so each surface keeps its own section title and extras.
 */
export function FrameFields({ target }: { target: FrameTarget }) {
  const [aspectLocked, setAspectLocked] = useState(true);
  const { rect, minSize = 1 } = target;
  const round1 = (v: number) => Math.round(v * 10) / 10;

  const commitWidth = (width: number) => {
    target.setRect(
      aspectLocked && rect.width > 0
        ? { width, height: Math.max(minSize, (width * rect.height) / rect.width) }
        : { width },
    );
  };
  const commitHeight = (height: number) => {
    target.setRect(
      aspectLocked && rect.height > 0
        ? { height, width: Math.max(minSize, (height * rect.width) / rect.height) }
        : { height },
    );
  };

  return (
    <>
      <FieldRow label="Align" title="Align to the safe area / canvas center">
        <div className="flex flex-1 gap-px">
          {ALIGNMENTS.map(({ key, title, Icon }) => (
            <Button
              key={key}
              variant="ghost"
              size="icon-xs"
              className="flex-1"
              title={title}
              onClick={() => target.setRect(alignFrame(target, key))}
            >
              <Icon />
            </Button>
          ))}
        </div>
      </FieldRow>
      <NumberField
        label="X"
        value={round1(rect.x)}
        unit="px"
        scrubPerPx={1}
        onCommit={(x) => target.setRect({ x })}
        controls={target.controls?.("x")}
      />
      <NumberField
        label="Y"
        value={round1(rect.y)}
        unit="px"
        scrubPerPx={1}
        onCommit={(y) => target.setRect({ y })}
        controls={target.controls?.("y")}
      />
      <NumberField
        label="Width"
        value={Math.round(rect.width)}
        min={minSize}
        unit="px"
        scrubPerPx={1}
        onCommit={commitWidth}
        controls={
          <>
            <Button
              variant="ghost"
              size="icon-xs"
              title={
                aspectLocked
                  ? "Aspect locked — width and height resize together"
                  : "Aspect free — width and height resize independently"
              }
              aria-pressed={aspectLocked}
              onClick={() => setAspectLocked((value) => !value)}
            >
              {aspectLocked ? <LockIcon /> : <LockOpenIcon />}
            </Button>
            {target.controls?.("width")}
          </>
        }
      />
      <NumberField
        label="Height"
        value={Math.round(rect.height)}
        min={minSize}
        unit="px"
        scrubPerPx={1}
        onCommit={commitHeight}
        controls={target.controls?.("height")}
      />
      {target.rotation && (
        <NumberField
          label="Rotation"
          value={round1(target.rotation.value)}
          min={-180}
          max={180}
          unit="°"
          scrubPerPx={0.5}
          onCommit={target.rotation.set}
          controls={target.controls?.("rotation")}
        />
      )}
    </>
  );
}

"use client";

import { useState } from "react";
import { SwatchIcon, Trash2Icon } from "@/lib/hugeicons";
import { useEditor, useProject } from "@mcut/react";
import { createPresetId, listPresets } from "@mcut/timeline";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";

/**
 * The ONE preset affordance, shared by every inspector section that opts in
 * (Figma styles, loosely): a swatch button on the section header that lists
 * the project's presets for this surface, applies one on click, and saves
 * the current values under a name. Presets are pure data on the project
 * (`project.presets`); this menu never interprets `values` — the section
 * captures them in `getValues` and writes them back in `onApply`, so the
 * same component serves element styles and multicam slot styles alike.
 */
export function PresetMenu({
  kind,
  getValues,
  onApply,
  className,
}: {
  /** Preset namespace this section saves into (e.g. "effects", "slot-style"). */
  kind: string;
  /** Capture the section's current values for "Save preset". */
  getValues: () => Record<string, unknown>;
  /** Write a preset's values back through the section's normal commands. */
  onApply: (values: Record<string, unknown>) => void;
  className?: string;
}) {
  const engine = useEditor();
  const project = useProject();
  const presets = listPresets(project, kind);
  const [open, setOpen] = useState(false);

  const save = () => {
    const name = window.prompt("Save the current settings as a preset:");
    if (!name?.trim()) return;
    try {
      engine.dispatch({
        type: "savePreset",
        preset: { id: createPresetId(), name: name.trim(), kind, values: getValues() },
      });
      toast.success(`"${name.trim()}" saved — apply it from any matching section`);
    } catch {
      toast.error("Could not save the preset");
    }
  };

  const apply = (values: Record<string, unknown>) => {
    try {
      onApply(values);
      setOpen(false);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Could not apply the preset");
    }
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger
        render={
          <Button
            variant="ghost"
            size="icon-xs"
            className={cn("size-5 text-muted-foreground", className)}
            title="Presets"
          />
        }
      >
        <SwatchIcon />
      </PopoverTrigger>
      <PopoverContent className="w-56 p-1" align="end">
        {presets.length === 0 && (
          <p className="px-2 py-1.5 text-2xs text-muted-foreground">
            No presets yet — save the current settings to reuse them on any matching section.
          </p>
        )}
        {presets.map((preset) => (
          <div key={preset.id} className="group/preset flex items-center gap-1">
            <button
              type="button"
              className="h-6 flex-1 truncate rounded-sm px-2 text-left text-xs hover:bg-foreground/5"
              onClick={() => apply(preset.values)}
            >
              {preset.name}
            </button>
            <Button
              variant="ghost"
              size="icon-xs"
              className="opacity-0 group-hover/preset:opacity-100"
              title={`Delete "${preset.name}"`}
              onClick={() => engine.dispatch({ type: "removePreset", presetId: preset.id })}
            >
              <Trash2Icon />
            </Button>
          </div>
        ))}
        <div className={cn(presets.length > 0 && "mt-1 border-t pt-1")}>
          <button
            type="button"
            className="h-6 w-full rounded-sm px-2 text-left text-xs text-muted-foreground hover:bg-foreground/5 hover:text-foreground"
            onClick={save}
          >
            Save current as preset…
          </button>
        </div>
      </PopoverContent>
    </Popover>
  );
}

