"use client";

import { useEffect } from "react";
import {
  createEditorOperatorRegistry,
  OperatorError,
  registerCoreOperators,
} from "@mcut/editor";
import { useEditor } from "@mcut/react";
import {
  CommandError,
  ProjectFormatError,
  getProjectCaptions,
  getProjectMediaContext,
  getProjectTranscript,
  summarizeProject,
  type EditorEngine,
  type Project,
  type ProjectTranscriptOptions,
} from "@mcut/timeline";
import { searchCaptions } from "@mcut/transcription";
import { toast } from "sonner";
import {
  formatShortcut,
  getEditorAction,
  isActionEnabled,
  listEditorActions,
  runEditorAction,
} from "./action-registry";
import { editorClipboard } from "./editor-clipboard";
import { useEditorUI } from "./editor-ui";
import { ensureTranscriptForBridge } from "./live-mcp-transcript";

interface BridgeRequest {
  id: string;
  type: string;
  payload?: unknown;
}

interface CommandPayload {
  commandName: string;
  input?: Record<string, unknown>;
}

interface OperatorPayload {
  operatorId: string;
  input?: unknown;
}

interface ActionPayload {
  actionId: string;
}

const operators = registerCoreOperators(createEditorOperatorRegistry());
const DEFAULT_BRIDGE_PORT = "44737";

function viewState(engine: EditorEngine): string {
  const playback = engine.playback.state;
  const selection = engine.selection.elementIds;
  return (
    `Playhead: ${(playback.currentTimeMs / 1000).toFixed(2)}s` +
    ` (${playback.isPlaying ? "playing" : "paused"})` +
    ` · Selection: ${selection.length > 0 ? selection.join(", ") : "none"}`
  );
}

function summarize(engine: EditorEngine): string {
  return `${summarizeProject(engine.project)}\n${viewState(engine)}`;
}

function transcriptOptions(value: unknown): ProjectTranscriptOptions {
  if (!isRecord(value)) return {};
  return { includeWords: value.includeWords === true };
}

function transcriptQuery(value: unknown): string {
  if (!isRecord(value) || typeof value.query !== "string" || !value.query.trim()) {
    throw new Error("search_transcript requires a non-empty query string.");
  }
  return value.query.trim();
}

function searchProjectTranscript(project: Project, query: string): unknown {
  const captionRefs = getProjectCaptions(project);
  const captions = captionRefs.map((ref) => ref.caption);
  const byId = new Map<string, (typeof captionRefs)[number]>(
    captionRefs.map((ref) => [ref.caption.id, ref]),
  );
  const matches = searchCaptions(captions, query).map((match) => {
    const ref = byId.get(match.captionId);
    const text = ref?.caption.text ?? "";
    return {
      ...match,
      text: text.slice(match.startChar, match.endChar),
      captionText: text,
      trackId: ref?.trackId,
      trackName: ref?.trackName,
      startMs: match.timeMs,
      endMs: match.endTimeMs,
    };
  });
  return { query, count: matches.length, matches };
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function commandPayload(value: unknown): CommandPayload {
  if (!isRecord(value) || typeof value.commandName !== "string") {
    throw new Error("Invalid dispatch_command payload.");
  }
  return {
    commandName: value.commandName,
    input: isRecord(value.input) ? value.input : {},
  };
}

function operatorPayload(value: unknown): OperatorPayload {
  if (!isRecord(value) || typeof value.operatorId !== "string") {
    throw new Error("Invalid run_operator payload.");
  }
  return {
    operatorId: value.operatorId,
    input: value.input ?? {},
  };
}

function actionPayload(value: unknown): ActionPayload {
  if (!isRecord(value) || typeof value.actionId !== "string") {
    throw new Error("Invalid run_action payload.");
  }
  return { actionId: value.actionId };
}

function serializeError(error: unknown) {
  if (
    error instanceof CommandError ||
    error instanceof ProjectFormatError ||
    error instanceof OperatorError
  ) {
    return { name: error.name, code: error.code, message: error.message };
  }
  return {
    name: error instanceof Error ? error.name : "Error",
    message: error instanceof Error ? error.message : String(error),
  };
}

async function handleRequest(
  engine: EditorEngine,
  ui: ReturnType<typeof useEditorUI>,
  request: BridgeRequest,
): Promise<unknown> {
  const context = { engine, ui, clipboard: editorClipboard };
  switch (request.type) {
    case "get_summary":
      return summarize(engine);
    case "get_project":
      return engine.toJSON();
    case "get_media_context":
      return getProjectMediaContext(engine.project, {
        playback: engine.playback.state,
        selection: engine.selection,
      });
    case "get_transcript":
      return getProjectTranscript(engine.project, transcriptOptions(request.payload));
    case "search_transcript":
      return searchProjectTranscript(engine.project, transcriptQuery(request.payload));
    case "ensure_transcript":
      return await ensureTranscriptForBridge(engine, request.payload);
    case "list_operators":
      return operators.listAvailable({ engine }).map((operator) => ({
        id: operator.id,
        label: operator.label,
        category: operator.category,
        enabled: operator.enabled,
        disabledReason: operator.disabledReason,
        tool: `operator_${operator.id.replace(/[^A-Za-z0-9_-]/g, "_")}`,
        description: operator.description,
      }));
    case "list_actions":
      return listEditorActions().map((action) => ({
        id: action.id,
        label: action.label,
        category: action.category,
        enabled: isActionEnabled(action, context),
        shortcut: formatShortcut(action.shortcut),
        palette: action.palette ?? true,
        operator: action.operator?.id,
      }));
    case "undo":
      return engine.undo();
    case "redo":
      return engine.redo();
    case "run_operator": {
      const { operatorId, input } = operatorPayload(request.payload);
      return await operators.run(operatorId, { engine }, input);
    }
    case "dispatch_command": {
      const { commandName, input } = commandPayload(request.payload);
      engine.dispatch({ type: commandName, ...input });
      return null;
    }
    case "run_action": {
      const { actionId } = actionPayload(request.payload);
      const action = getEditorAction(actionId);
      if (!action) throw new Error(`Unknown editor action "${actionId}".`);
      if (!isActionEnabled(action, context)) {
        throw new Error(`Editor action "${actionId}" is disabled.`);
      }
      runEditorAction(action, context);
      return null;
    }
    default:
      throw new Error(`Unknown live MCP request "${request.type}".`);
  }
}

function bridgeConfig(): { port: string; token: string | null; quiet: boolean } | null {
  if (typeof window === "undefined") return null;
  const params = new URLSearchParams(window.location.search);
  const port = params.get("mcpBridge");
  const token = params.get("mcpToken");
  if (port) return { port, token, quiet: false };
  return { port: DEFAULT_BRIDGE_PORT, token: null, quiet: true };
}

export function LiveMcpBridge() {
  const engine = useEditor();
  const ui = useEditorUI();

  useEffect(() => {
    const config = bridgeConfig();
    if (!config) return;

    let stopped = false;
    let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
    let socket: WebSocket | null = null;

    const scheduleConnect = () => {
      reconnectTimer = setTimeout(start, config.quiet ? 5000 : 1000);
    };

    const start = () => {
      if (!config.quiet) {
        connect();
        return;
      }
      fetch(`http://127.0.0.1:${config.port}/status`, { mode: "no-cors" })
        .then(() => connect())
        .catch(() => {
          if (!stopped) scheduleConnect();
        });
    };

    const connect = () => {
      if (stopped) return;
      const url = new URL(`ws://127.0.0.1:${config.port}/mcut-mcp`);
      if (config.token) url.searchParams.set("token", config.token);
      socket = new WebSocket(url);

      socket.addEventListener("open", () => {
        socket?.send(
          JSON.stringify({
            type: "hello",
            payload: {
              projectName: engine.project.name,
              userAgent: window.navigator.userAgent,
            },
          }),
        );
        if (!config.quiet) toast.success("Live MCP connected");
      });

      socket.addEventListener("message", (event) => {
        void (async () => {
          let request: BridgeRequest | null = null;
          try {
            request = JSON.parse(String(event.data)) as BridgeRequest;
            const result = await handleRequest(engine, ui, request);
            socket?.send(JSON.stringify({ id: request.id, ok: true, result }));
          } catch (error) {
            socket?.send(
              JSON.stringify({
                id: request?.id,
                ok: false,
                error: serializeError(error),
              }),
            );
          }
        })();
      });

      socket.addEventListener("close", () => {
        if (stopped) return;
        scheduleConnect();
      });

      socket.addEventListener("error", () => {
        socket?.close();
      });
    };

    start();

    return () => {
      stopped = true;
      if (reconnectTimer) clearTimeout(reconnectTimer);
      socket?.close();
    };
  }, [engine, ui]);

  return null;
}

"use client";

import { extractAudioToWav } from "@mcut/media";
import {
  buildApplyCaptionsCommand,
  type TranscribeOptions,
  type TranscriptResult,
} from "@mcut/transcription";
import {
  getElementLocation,
  getProjectCaptions,
  getProjectTranscript,
  getSourceSpanMs,
  rangesOverlap,
  type AssetRef,
  type AudioElement,
  type EditorEngine,
  type ElementId,
  type ProjectTranscriptContext,
  type VideoElement,
} from "@mcut/timeline";
import {
  isLocalTranscriptionSupported,
  transcribeOnDevice,
} from "./local-transcription";

type CaptionableElement = VideoElement | AudioElement;

interface TranscriptionSource {
  asset: AssetRef;
  element: CaptionableElement;
}

export interface EnsureTranscriptPayload {
  elementId?: string;
  replace?: boolean;
  language?: string;
}

export interface EnsureTranscriptDeps {
  isLocalTranscriptionSupported: () => boolean;
  extractAudioToWav: (src: string) => Promise<Blob | null>;
  transcribeOnDevice: (
    audio: Blob,
    options?: TranscribeOptions,
  ) => Promise<TranscriptResult>;
}

export interface EnsureTranscriptResult {
  applied: boolean;
  reason?: string;
  source: {
    elementId: string;
    assetId: string;
    assetName?: string;
    startMs: number;
    endMs: number;
    sourceStartMs: number;
    sourceEndMs: number;
  };
  transcript: ProjectTranscriptContext;
}

const browserDeps: EnsureTranscriptDeps = {
  isLocalTranscriptionSupported,
  extractAudioToWav: (src) => extractAudioToWav(src),
  transcribeOnDevice,
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function parsePayload(value: unknown): EnsureTranscriptPayload {
  if (!isRecord(value)) return {};
  return {
    ...(typeof value.elementId === "string" ? { elementId: value.elementId } : {}),
    ...(typeof value.replace === "boolean" ? { replace: value.replace } : {}),
    ...(typeof value.language === "string" && value.language.trim()
      ? { language: value.language.trim() }
      : {}),
  };
}

function isCaptionableElement(element: unknown): element is CaptionableElement {
  return (
    typeof element === "object" &&
    element !== null &&
    "type" in element &&
    (element.type === "video" || element.type === "audio")
  );
}

function pickTranscriptionSource(
  engine: EditorEngine,
  payload: EnsureTranscriptPayload,
): TranscriptionSource {
  const project = engine.project;
  if (payload.elementId) {
    const location = getElementLocation(project, payload.elementId as ElementId);
    if (!location || !isCaptionableElement(location.element)) {
      throw new Error(`Element "${payload.elementId}" is not a video or audio clip.`);
    }
    const asset = project.assets[location.element.assetId];
    if (!asset) throw new Error(`Element "${payload.elementId}" has no asset.`);
    return { asset, element: location.element };
  }

  for (const elementId of engine.selection.elementIds) {
    const location = getElementLocation(project, elementId);
    if (!location || !isCaptionableElement(location.element)) continue;
    const asset = project.assets[location.element.assetId];
    if (asset) return { asset, element: location.element };
  }

  const captionable = project.tracks
    .flatMap((track) => track.elements)
    .filter((element): element is CaptionableElement =>
      isCaptionableElement(element) && !!project.assets[element.assetId],
    )
    .sort((a, b) => a.startMs - b.startMs);
  const element =
    captionable.find((candidate) => candidate.type === "video") ??
    captionable.find((candidate) => candidate.type === "audio");
  if (!element) throw new Error("Add a video or audio clip to the timeline first.");
  return { asset: project.assets[element.assetId]!, element };
}

function assertBridgeTranscriptionSupported(source: TranscriptionSource): void {
  if (source.element.reversed) {
    throw new Error("Bridge transcription does not support reversed clips yet.");
  }
  if (source.element.timeMap) {
    throw new Error("Bridge transcription does not support speed-ramped clips yet.");
  }
}

function overlappingCaptions(engine: EditorEngine, source: TranscriptionSource) {
  return getProjectCaptions(engine.project).filter(({ caption }) =>
    rangesOverlap(
      caption.startMs,
      caption.durationMs,
      source.element.startMs,
      source.element.durationMs,
    ),
  );
}

function sourceResult(source: TranscriptionSource): EnsureTranscriptResult["source"] {
  const sourceStartMs = source.element.trimStartMs;
  const sourceEndMs = sourceStartMs + getSourceSpanMs(source.element);
  return {
    elementId: source.element.id,
    assetId: source.asset.id,
    ...(source.asset.name ? { assetName: source.asset.name } : {}),
    startMs: source.element.startMs,
    endMs: source.element.startMs + source.element.durationMs,
    sourceStartMs,
    sourceEndMs,
  };
}

export async function ensureTranscriptForBridge(
  engine: EditorEngine,
  value: unknown,
  deps: EnsureTranscriptDeps = browserDeps,
): Promise<EnsureTranscriptResult> {
  const payload = parsePayload(value);
  const source = pickTranscriptionSource(engine, payload);
  const sourceInfo = sourceResult(source);
  const existing = overlappingCaptions(engine, source);

  if (!payload.replace && existing.length > 0) {
    return {
      applied: false,
      reason: "Transcript captions already overlap the target clip.",
      source: sourceInfo,
      transcript: getProjectTranscript(engine.project, { includeWords: true }),
    };
  }

  assertBridgeTranscriptionSupported(source);
  if (!deps.isLocalTranscriptionSupported()) {
    throw new Error(
      "Local Whisper transcription is not supported in this browser. Use a WebGPU-capable browser with enough memory.",
    );
  }

  const wav = await deps.extractAudioToWav(source.asset.src);
  if (!wav) {
    throw new Error(`"${source.asset.name ?? source.asset.id}" has no audio track.`);
  }

  const options = payload.language ? { language: payload.language } : undefined;
  const result = await deps.transcribeOnDevice(wav, options);
  const command = buildApplyCaptionsCommand(result, {
    replace: false,
    timeOffsetMs: source.element.startMs,
    sourceStartMs: source.element.trimStartMs,
    sourceEndMs: source.element.trimStartMs + getSourceSpanMs(source.element),
  });
  if (!Array.isArray(command.captions) || command.captions.length === 0) {
    throw new Error("Transcription produced no captions for the target clip.");
  }

  engine.transact(() => {
    if (payload.replace) {
      for (const { caption } of overlappingCaptions(engine, source)) {
        engine.dispatch({ type: "removeElement", elementId: caption.id });
      }
    }
    engine.dispatch(command);
  });

  return {
    applied: true,
    source: sourceInfo,
    transcript: getProjectTranscript(engine.project, { includeWords: true }),
  };
}

import {
  collectSnapTargets as collectTimelineSnapTargets,
  type Project,
  type SnapTarget,
} from "@mcut/timeline";

// The snap engine itself (targets, nearest-target search, frame fallback)
// lives in @mcut/timeline so every gesture and any host app agree on policy;
// this module keeps the app-shaped entry points.
export { snapClip, snapTime } from "@mcut/timeline";
export type { SnapClipResult, SnapOptions, SnapResult, SnapTarget } from "@mcut/timeline";

/**
 * Magnetic snap targets: timeline zero, the playhead, markers, and every
 * clip edge (except the elements being dragged). Sorted by time.
 */
export function collectSnapTargets(
  project: Project,
  playheadMs: number,
  excludeElementIds: ReadonlySet<string> = new Set(),
): SnapTarget[] {
  return collectTimelineSnapTargets(project, { playheadMs, excludeElementIds });
}

/** Convert a pointer clientX into timeline ms for a lane element. */
export function pointerToTimelineMs(
  clientX: number,
  laneRect: { left: number },
  pxPerMs: number,
): number {
  return Math.max(0, Math.round((clientX - laneRect.left) / pxPerMs));
}

