"use client";

import { useEffect, useRef, useState, type PointerEvent as ReactPointerEvent } from "react";
import { useEditor } from "@mcut/react";
import {
  getKeyframes,
  type AnimatableProperty,
  type Easing,
  type Keyframe,
  type TimelineElement,
} from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { useEditorState } from "@mcut/react";
import { getElementLocation, type ElementId } from "@mcut/timeline";

/**
 * The graph editor: value-vs-time for one property of one clip, AE-style.
 * Keyframes are draggable points (drag retimes + revalues); each segment's
 * easing is a cubic-bezier whose two handles you drag directly — mcut's
 * easing IS `cubicBezier`, so the mapping is 1:1, and the evaluator accepts
 * y outside 0..1, which is exactly how Overshoot/Anticipate work. A curve
 * library applies named beziers per segment (⌥-click: all segments).
 */

const W = 280;
const H = 150;
const PAD = 18;

/** Named curves (the Flow-plugin idea). x values stay in 0..1; y overshoots. */
export const CURVE_LIBRARY: Array<{ name: string; bezier: [number, number, number, number] }> = [
  { name: "Linear", bezier: [0.25, 0.25, 0.75, 0.75] },
  { name: "Smooth", bezier: [0.42, 0, 0.58, 1] },
  { name: "Snap", bezier: [0.7, 0, 0.2, 1] },
  { name: "Settle", bezier: [0.2, 0.8, 0.2, 1] },
  { name: "Overshoot", bezier: [0.34, 1.56, 0.64, 1] },
  { name: "Anticipate", bezier: [0.36, -0.36, 0.66, 1] },
];

function easingToBezier(easing: Easing | undefined): [number, number, number, number] {
  if (!easing || easing === "linear") return [0.25, 0.25, 0.75, 0.75];
  if (easing === "hold") return [0, 0, 1, 0]; // drawn as a step; handles hidden
  if (easing === "easeIn") return [0.42, 0, 1, 1];
  if (easing === "easeOut") return [0, 0, 0.58, 1];
  if (easing === "easeInOut") return [0.42, 0, 0.58, 1];
  return easing.cubicBezier;
}

interface Scale {
  toX: (timeMs: number) => number;
  toY: (value: number) => number;
  fromX: (x: number) => number;
  fromY: (y: number) => number;
}

function makeScale(track: readonly Keyframe[]): Scale {
  const t0 = track[0]!.timeMs;
  const t1 = Math.max(track[track.length - 1]!.timeMs, t0 + 1);
  const values = track.map((k) => k.value);
  let v0 = Math.min(...values);
  let v1 = Math.max(...values);
  if (v1 - v0 < 1e-6) {
    v0 -= 1;
    v1 += 1;
  }
  // Headroom for overshoot handles.
  const pad = (v1 - v0) * 0.25;
  v0 -= pad;
  v1 += pad;
  return {
    toX: (t) => PAD + ((t - t0) / (t1 - t0)) * (W - PAD * 2),
    toY: (v) => H - PAD - ((v - v0) / (v1 - v0)) * (H - PAD * 2),
    fromX: (x) => t0 + ((x - PAD) / (W - PAD * 2)) * (t1 - t0),
    fromY: (y) => v0 + ((H - PAD - y) / (H - PAD * 2)) * (v1 - v0),
  };
}

export function EasingGraph({
  element,
  property,
}: {
  element: TimelineElement;
  property: AnimatableProperty;
}) {
  const engine = useEditor();
  const track = getKeyframes(element, property);
  const [segment, setSegment] = useState(0);
  const svgRef = useRef<SVGSVGElement | null>(null);
  const dragRef = useRef<
    | { kind: "key"; index: number; fromMs: number }
    | { kind: "handle"; which: 1 | 2 }
    | null
  >(null);

  if (track.length < 2) {
    return (
      <p className="p-2 text-xs text-muted-foreground">
        Add at least two keyframes to edit the curve.
      </p>
    );
  }

  const scale = makeScale(track);
  const seg = Math.min(segment, track.length - 2);
  const from = track[seg]!;
  const to = track[seg + 1]!;
  const [bx1, by1, bx2, by2] = easingToBezier(from.easing);
  const isHold = from.easing === "hold";

  // Segment bezier control points in graph space.
  const cp = (bx: number, by: number) => ({
    x: scale.toX(from.timeMs + bx * (to.timeMs - from.timeMs)),
    y: scale.toY(from.value + by * (to.value - from.value)),
  });
  const p1 = cp(bx1, by1);
  const p2 = cp(bx2, by2);

  const pointer = (event: ReactPointerEvent) => {
    const rect = svgRef.current!.getBoundingClientRect();
    return { x: event.clientX - rect.left, y: event.clientY - rect.top };
  };

  const dispatch = (command: Record<string, unknown> & { type: string }) => {
    try {
      engine.dispatch(command);
    } catch {
      // Collision (duplicate time): keep last good state.
    }
  };

  const setSegmentBezier = (bezier: [number, number, number, number]) => {
    dispatch({
      type: "setKeyframeEasing",
      elementId: element.id,
      property,
      timeMs: from.timeMs,
      easing: { cubicBezier: bezier },
    });
  };

  const onPointerMove = (event: ReactPointerEvent) => {
    const drag = dragRef.current;
    if (!drag) return;
    const { x, y } = pointer(event);
    if (drag.kind === "key") {
      const keyframe = track[drag.index]!;
      const toMs = Math.round(scale.fromX(x));
      const value = Math.round(scale.fromY(y) * 1000) / 1000;
      dispatch({
        type: "setKeyframe",
        elementId: element.id,
        property,
        timeMs: drag.fromMs,
        value,
        ...(keyframe.easing !== undefined ? { easing: keyframe.easing } : {}),
      });
      if (drag.index !== 0 && toMs !== drag.fromMs) {
        const prev = track[drag.index - 1];
        const next = track[drag.index + 1];
        const clamped = Math.max(
          prev ? prev.timeMs + 1 : 0,
          Math.min(toMs, next ? next.timeMs - 1 : element.durationMs),
        );
        dispatch({
          type: "moveKeyframe",
          elementId: element.id,
          property,
          fromTimeMs: drag.fromMs,
          toTimeMs: clamped,
        });
        drag.fromMs = clamped;
      }
    } else {
      // Handle drag: x clamps to the segment (bezier x must be 0..1); y is
      // free — beyond the segment's value range = overshoot.
      const span = to.timeMs - from.timeMs;
      const bx = Math.max(0, Math.min(1, (scale.fromX(x) - from.timeMs) / span));
      const vSpan = to.value - from.value;
      const by = vSpan === 0 ? 0 : (scale.fromY(y) - from.value) / vSpan;
      const next: [number, number, number, number] =
        drag.which === 1 ? [bx, by, bx2, by2] : [bx1, by1, bx, by];
      setSegmentBezier(next.map((n) => Math.round(n * 100) / 100) as typeof next);
    }
  };

  const endDrag = (event: ReactPointerEvent) => {
    if (!dragRef.current) return;
    dragRef.current = null;
    engine.endTransaction();
    (event.currentTarget as Element).releasePointerCapture(event.pointerId);
  };

  // Full curve path: per-segment cubics in graph space.
  const path = track
    .slice(0, -1)
    .map((k, i) => {
      const n = track[i + 1]!;
      const [x1, y1, x2, y2] = easingToBezier(k.easing);
      const a = { x: scale.toX(k.timeMs), y: scale.toY(k.value) };
      const b = { x: scale.toX(n.timeMs), y: scale.toY(n.value) };
      if (k.easing === "hold") {
        return `M ${a.x} ${a.y} H ${b.x - 0.01} M ${b.x} ${b.y}`;
      }
      const c1 = {
        x: scale.toX(k.timeMs + x1 * (n.timeMs - k.timeMs)),
        y: scale.toY(k.value + y1 * (n.value - k.value)),
      };
      const c2 = {
        x: scale.toX(k.timeMs + x2 * (n.timeMs - k.timeMs)),
        y: scale.toY(k.value + y2 * (n.value - k.value)),
      };
      return `M ${a.x} ${a.y} C ${c1.x} ${c1.y} ${c2.x} ${c2.y} ${b.x} ${b.y}`;
    })
    .join(" ");

  return (
    <div className="flex flex-col gap-2">
      <svg
        ref={svgRef}
        width={W}
        height={H}
        className="touch-none rounded-lg bg-foreground/[0.04]"
        onPointerMove={onPointerMove}
        onPointerUp={endDrag}
        onPointerCancel={endDrag}
      >
        {/* midline */}
        <line x1={PAD} x2={W - PAD} y1={H / 2} y2={H / 2} stroke="currentColor" opacity={0.08} />
        <path d={path} fill="none" stroke="var(--color-primary)" strokeWidth={1.75} />
        {/* selected-segment handles */}
        {!isHold && (
          <>
            <line x1={scale.toX(from.timeMs)} y1={scale.toY(from.value)} x2={p1.x} y2={p1.y} stroke="currentColor" opacity={0.35} />
            <line x1={scale.toX(to.timeMs)} y1={scale.toY(to.value)} x2={p2.x} y2={p2.y} stroke="currentColor" opacity={0.35} />
            {([{ p: p1, which: 1 }, { p: p2, which: 2 }] as const).map(({ p, which }) => (
              <circle
                key={which}
                cx={p.x}
                cy={p.y}
                r={4.5}
                className="cursor-grab fill-card stroke-primary"
                strokeWidth={1.5}
                onPointerDown={(event) => {
                  event.stopPropagation();
                  dragRef.current = { kind: "handle", which };
                  engine.beginTransaction();
                  (event.currentTarget as Element).setPointerCapture(event.pointerId);
                }}
              />
            ))}
          </>
        )}
        {/* keyframes */}
        {track.map((k, i) => (
          <rect
            key={k.timeMs}
            x={scale.toX(k.timeMs) - 4}
            y={scale.toY(k.value) - 4}
            width={8}
            height={8}
            transform={`rotate(45 ${scale.toX(k.timeMs)} ${scale.toY(k.value)})`}
            className={cn(
              "cursor-grab stroke-card",
              i === seg || i === seg + 1 ? "fill-primary" : "fill-muted-foreground",
            )}
            strokeWidth={1}
            onPointerDown={(event) => {
              event.stopPropagation();
              setSegment(Math.min(i, track.length - 2));
              dragRef.current = { kind: "key", index: i, fromMs: k.timeMs };
              engine.beginTransaction();
              (event.currentTarget as Element).setPointerCapture(event.pointerId);
            }}
          />
        ))}
      </svg>
      <div className="flex flex-wrap gap-1">
        {CURVE_LIBRARY.map((curve) => (
          <button
            key={curve.name}
            type="button"
            title={`${curve.name} — click: this segment · ⌥-click: every segment`}
            className="flex flex-col items-center gap-0.5 rounded-md px-1.5 py-1 hover:bg-foreground/5"
            onClick={(event) => {
              if (event.altKey) {
                engine.transact(() => {
                  for (const k of track.slice(0, -1)) {
                    dispatch({
                      type: "setKeyframeEasing",
                      elementId: element.id,
                      property,
                      timeMs: k.timeMs,
                      easing: { cubicBezier: curve.bezier },
                    });
                  }
                });
              } else {
                setSegmentBezier(curve.bezier);
              }
            }}
          >
            <CurveSparkline bezier={curve.bezier} />
            <span className="text-2xs text-muted-foreground">{curve.name}</span>
          </button>
        ))}
      </div>
      <p className="text-2xs text-muted-foreground">
        Drag diamonds to retime/revalue · drag the round handles to shape the curve (above the
        range = overshoot) · segment {seg + 1}/{track.length - 1}
      </p>
    </div>
  );
}

function CurveSparkline({ bezier: [x1, y1, x2, y2] }: { bezier: [number, number, number, number] }) {
  const sw = 30;
  const sh = 18;
  const sx = (v: number) => 2 + v * (sw - 4);
  const sy = (v: number) => sh - 3 - v * (sh - 6);
  return (
    <svg width={sw} height={sh} className="text-primary">
      <path
        d={`M ${sx(0)} ${sy(0)} C ${sx(x1)} ${sy(y1)} ${sx(x2)} ${sy(y2)} ${sx(1)} ${sy(1)}`}
        fill="none"
        stroke="currentColor"
        strokeWidth={1.25}
      />
    </svg>
  );
}

/** Popover entry: the ∿ curve button next to a property's keyframe controls. */
export function EasingEditorButton({
  element,
  property,
}: {
  element: TimelineElement;
  property: AnimatableProperty;
}) {
  return (
    <Popover>
      <PopoverTrigger
        render={
          <Button
            variant="ghost"
            size="icon-xs"
            aria-label="Open curve editor"
            title="Curve editor (graph)"
          />
        }
      >
        <span className="font-mono text-xs">∿</span>
      </PopoverTrigger>
      <PopoverContent align="end" className="w-auto gap-2 p-3">
        <EasingGraph element={element} property={property} />
      </PopoverContent>
    </Popover>
  );
}

/**
 * Listens for "mcut:open-curve-editor" (fired from the keyframe easing menu)
 * and shows the graph in a dialog. Mount once in the shell.
 */
export function CurveEditorHost() {
  const [target, setTarget] = useState<{ elementId: ElementId; property: AnimatableProperty } | null>(
    null,
  );
  useEffect(() => {
    const onOpen = (event: Event) => {
      const detail = (event as CustomEvent).detail as {
        elementId: ElementId;
        property: AnimatableProperty;
      };
      setTarget(detail);
    };
    window.addEventListener("mcut:open-curve-editor", onOpen);
    return () => window.removeEventListener("mcut:open-curve-editor", onOpen);
  }, []);

  const element = useEditorState((s) =>
    target ? getElementLocation(s.project, target.elementId)?.element : undefined,
  );

  return (
    <Dialog open={Boolean(target && element)} onOpenChange={(open) => !open && setTarget(null)}>
      <DialogContent className="w-auto max-w-none">
        <DialogHeader>
          <DialogTitle className="text-sm">
            Curve editor — <span className="font-mono text-xs">{target?.property}</span>
          </DialogTitle>
        </DialogHeader>
        {target && element && <EasingGraph element={element} property={target.property} />}
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { renderFrame } from "@mcut/compositor";
import { useEditorContext, useEditorState, usePlayback, useSelection } from "@mcut/react";
import { getActiveAngleIndex, type Layout, type MulticamElement, type Project } from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { PanelSectionLabel } from "./editor-primitives";
import { findTargetMulticam, switchToLayout } from "./multicam-ui";
import { useEditorUI } from "./editor-ui";

/**
 * The multicam layout bank (Premiere's angle monitor adapted to layouts):
 * one live tile per project layout. Click or press 1–9 — while playing it
 * CUTS at the playhead; while paused it CORRECTS the span under it.
 */

const TILE_FPS_MS = 120; // ~8fps live tiles — smooth enough, cheap enough

function projectWithForcedLayout(
  project: Project,
  multicam: MulticamElement,
  layoutId: string,
): Project {
  return {
    ...project,
    tracks: project.tracks.map((track) => ({
      ...track,
      elements: track.elements.map((element) =>
        element.id === multicam.id && element.type === "multicam"
          ? { ...element, angles: [{ atMs: 0, layoutId }] }
          : element,
      ),
    })),
  };
}

function LayoutTile({
  project,
  multicam,
  layout,
  index,
  active,
}: {
  project: Project;
  multicam: MulticamElement;
  layout: Layout;
  index: number;
  active: boolean;
}) {
  const { engine, pool } = useEditorContext();
  const { editingLayoutId, setEditingLayoutId } = useEditorUI();
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const lastDrawRef = useRef(0);

  // Live tile: redraw from the shared preview pool, throttled.
  const tick = usePlayback((s) => Math.floor(s.currentTimeMs / TILE_FPS_MS));
  useEffect(() => {
    void tick;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const now = performance.now();
    if (now - lastDrawRef.current < TILE_FPS_MS / 2) return;
    lastDrawRef.current = now;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    const forced = projectWithForcedLayout(project, multicam, layout.id);
    ctx.save();
    ctx.scale(canvas.width / project.width, canvas.height / project.height);
    renderFrame(ctx, forced, engine.playback.state.currentTimeMs, { source: pool });
    ctx.restore();
  });

  return (
    <button
      type="button"
      title={`${layout.name} — ${index + 1} cuts while playing, corrects while paused`}
      className={cn(
        "group relative w-full overflow-hidden rounded-lg text-left transition-shadow",
        active ? "ring-2 ring-primary" : "ring-1 ring-foreground/10 hover:ring-foreground/30",
      )}
      onClick={() => switchToLayout(engine, multicam, layout.id)}
    >
      <canvas
        ref={canvasRef}
        width={192}
        height={Math.round((192 * project.height) / project.width)}
        className="block w-full"
      />
      <span className="absolute top-1 left-1 rounded-sm bg-overlay/65 px-1 font-mono text-2xs text-overlay-foreground">
        {index + 1}
      </span>
      <span className="absolute right-1 bottom-1 left-1 truncate rounded-sm bg-overlay/55 px-1 py-0.5 text-2xs text-overlay-foreground/90">
        {layout.name}
      </span>
      <span
        role="button"
        tabIndex={-1}
        title={editingLayoutId === layout.id ? "Stop editing slots" : "Edit slots on the canvas"}
        className={cn(
          "absolute top-1 right-1 hidden rounded-sm bg-overlay/65 px-1 text-2xs text-overlay-foreground/90 group-hover:block",
          editingLayoutId === layout.id && "block bg-primary text-primary-foreground",
        )}
        onClick={(event) => {
          event.stopPropagation();
          setEditingLayoutId(editingLayoutId === layout.id ? null : layout.id);
        }}
      >
        ✎
      </span>
    </button>
  );
}

export function LayoutBank({ className }: { className?: string }) {
  const { engine } = useEditorContext();
  const project = useEditorState((s) => s.project);
  const selection = useSelection();
  const playheadMs = usePlayback((s) => s.currentTimeMs);
  const target = findTargetMulticam(project, selection.elementIds, playheadMs);

  if (!target) {
    const selectedVideos = selection.elementIds.filter((id) =>
      project.tracks.some((t) => t.elements.some((e) => e.id === id && e.type === "video")),
    );
    const count = selectedVideos.length;
    return (
      <div
        className={cn(
          "flex w-48 shrink-0 flex-col justify-center gap-2 p-3 text-xs text-muted-foreground",
          className,
        )}
      >
        <p className="font-medium text-foreground">No multicam yet</p>
        <p>
          Fastest: in the Media bin, click your screen and camera videos — a “New multicam”
          panel appears where you pick which is which.
        </p>
        <p>From the timeline instead: select both clips (click one, shift-click the other), then:</p>
        <Button
          size="xs"
          disabled={count === 0}
          onClick={() => {
            try {
              engine.dispatch({ type: "createMulticam", elementIds: selectedVideos });
            } catch {
              // Selection changed underneath: state resyncs.
            }
          }}
        >
          Create multicam
        </Button>
        <p className="text-2xs">
          {count === 0
            ? "Nothing selected on the timeline yet — selecting files in the media bin doesn't count."
            : count === 1
              ? "1 clip selected — shift-click the other to get screen + camera."
              : count === 2
                ? "2 clips selected — bottom layer becomes the screen, top layer the camera. Swap roles anytime in the properties panel."
                : `${count} clips selected — assign roles in the properties panel after creating.`}
        </p>
      </div>
    );
  }

  const localMs = playheadMs - target.element.startMs;
  const activeIndex = getActiveAngleIndex(target.element.angles, localMs);
  const activeLayoutId = target.element.angles[activeIndex]?.layoutId;

  return (
    <div className={cn("flex w-48 shrink-0 flex-col gap-2 overflow-y-auto scroll-mask-b p-2", className)}>
      <PanelSectionLabel>Layouts · 1–{Math.min(9, project.layouts.length)}</PanelSectionLabel>
      {project.layouts.map((layout, index) => (
        <LayoutTile
          key={layout.id}
          project={project}
          multicam={target.element}
          layout={layout}
          index={index}
          active={layout.id === activeLayoutId}
        />
      ))}
    </div>
  );
}

"use client";

import { useEffect, useRef, useState, type PointerEvent as ReactPointerEvent } from "react";
import { useEditor, useEditorState } from "@mcut/react";
import type { EditorEngine, Layout, LayoutSlot } from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { useEditorUI } from "./editor-ui";
import { clamp, clamp01 } from "./math";
import { findTargetMulticam } from "./multicam-ui";

/**
 * On-canvas direct manipulation for a multicam layout, Figma-style: slots
 * are draggable boxes with eight resize handles (corners keep the aspect,
 * Shift frees it; edges stretch one axis), drags snap to the safe area /
 * canvas center / sibling slots with guide lines (⌘ disables), arrows nudge
 * by a pixel, and double-clicking a cover slot enters crop mode where
 * dragging pans the source inside the frame. Everything with a value — fit,
 * radius, shadow, aspect, exact position — lives in the inspector
 * (LayoutSlotInspector in properties-layout-slot.tsx), keyed off the shared
 * editingSlotIndex edit state. Every edit dispatches saveLayout, so the bank
 * tiles and program output restyle live.
 */

const MIN_SIZE = 0.05;
const CLICK_SLOP_PX = 4;
const SNAP_PX = 8;

/** Safe-area margin: 5% of the canvas short edge (uniform in pixels). */
export const SAFE_MARGIN = 0.05;

/** The safe-area rect in normalized canvas coordinates. */
export function safeAreaRect(width: number, height: number): LayoutSlot["rect"] {
  const margin = SAFE_MARGIN * Math.min(width, height);
  return {
    x: margin / width,
    y: margin / height,
    w: 1 - (2 * margin) / width,
    h: 1 - (2 * margin) / height,
  };
}

export function roundRect(rect: LayoutSlot["rect"]): LayoutSlot["rect"] {
  return {
    x: Math.round(rect.x * 1000) / 1000,
    y: Math.round(rect.y * 1000) / 1000,
    w: Math.round(rect.w * 1000) / 1000,
    h: Math.round(rect.h * 1000) / 1000,
  };
}

/** Patch one slot of a layout (shared with the inspector). */
export function saveLayoutSlot(
  engine: EditorEngine,
  layout: Layout,
  index: number,
  patch: Partial<LayoutSlot>,
  options?: { history?: boolean },
): void {
  try {
    engine.dispatch(
      {
        type: "saveLayout",
        layout: {
          ...layout,
          slots: layout.slots.map((s, i) => (i === index ? { ...s, ...patch } : s)),
        },
      },
      options,
    );
  } catch {
    // Layout vanished mid-edit.
  }
}

const round3 = (value: number) => Math.round(value * 1000) / 1000;

/** Closest snap candidate to any of `positions` within `threshold`. */
function snapAxis(
  positions: number[],
  candidates: number[],
  threshold: number,
): { delta: number; guide: number | null } {
  let best: { delta: number; guide: number } | null = null;
  for (const position of positions) {
    for (const candidate of candidates) {
      const delta = candidate - position;
      if (Math.abs(delta) <= threshold && (!best || Math.abs(delta) < Math.abs(best.delta))) {
        best = { delta, guide: candidate };
      }
    }
  }
  return best ?? { delta: 0, guide: null };
}

/** Snap targets on one axis: canvas edges/center, safe area, sibling slots. */
function axisCandidates(
  layout: Layout,
  skipIndex: number,
  safe: LayoutSlot["rect"],
  axis: "x" | "y",
): number[] {
  const candidates =
    axis === "x" ? [0, safe.x, 0.5, safe.x + safe.w, 1] : [0, safe.y, 0.5, safe.y + safe.h, 1];
  layout.slots.forEach((slot, i) => {
    if (i === skipIndex) return;
    const start = axis === "x" ? slot.rect.x : slot.rect.y;
    const length = axis === "x" ? slot.rect.w : slot.rect.h;
    candidates.push(start, start + length / 2, start + length);
  });
  return candidates;
}

type HandleId = "nw" | "n" | "ne" | "e" | "se" | "s" | "sw" | "w";

const HANDLES: ReadonlyArray<{ id: HandleId; x: number; y: number; cursor: string }> = [
  { id: "nw", x: 0, y: 0, cursor: "nwse-resize" },
  { id: "n", x: 0.5, y: 0, cursor: "ns-resize" },
  { id: "ne", x: 1, y: 0, cursor: "nesw-resize" },
  { id: "e", x: 1, y: 0.5, cursor: "ew-resize" },
  { id: "se", x: 1, y: 1, cursor: "nwse-resize" },
  { id: "s", x: 0.5, y: 1, cursor: "ns-resize" },
  { id: "sw", x: 0, y: 1, cursor: "nesw-resize" },
  { id: "w", x: 0, y: 0.5, cursor: "ew-resize" },
];

interface Guides {
  x: number | null;
  y: number | null;
  /** True while a drag is live (shows the safe-area outline). */
  active: boolean;
}

const NO_GUIDES: Guides = { x: null, y: null, active: false };

function SlotBox({
  layout,
  slot,
  index,
  selected,
  cropping,
  sourceSize,
  onSelect,
  onToggleCrop,
  setGuides,
}: {
  layout: Layout;
  slot: LayoutSlot;
  index: number;
  selected: boolean;
  cropping: boolean;
  /** Natural pixel size of the source filling this slot (for crop panning). */
  sourceSize: { width: number; height: number } | null;
  onSelect: (index: number) => void;
  onToggleCrop: (index: number) => void;
  setGuides: (guides: Guides) => void;
}) {
  const engine = useEditor();
  const dragRef = useRef<{
    mode: "move" | "resize" | "crop";
    handle: HandleId | null;
    startX: number;
    startY: number;
    rect: LayoutSlot["rect"];
    focus: { x: number; y: number };
    /** How many container px of the source overflow the slot per axis (crop). */
    overflow: { x: number; y: number };
    container: DOMRect;
    moved: boolean;
  } | null>(null);

  const save = (patch: Partial<LayoutSlot>) => saveLayoutSlot(engine, layout, index, patch);

  const begin = (
    mode: "move" | "resize" | "crop",
    event: ReactPointerEvent<HTMLElement>,
    handle: HandleId | null = null,
  ) => {
    event.stopPropagation();
    const container = (
      event.currentTarget.closest("[data-mcut-slot-editor]") as HTMLElement
    ).getBoundingClientRect();
    const overflow = { x: 0, y: 0 };
    if (mode === "crop" && sourceSize) {
      const slotW = slot.rect.w * container.width;
      const slotH = slot.rect.h * container.height;
      const scale = Math.max(slotW / sourceSize.width, slotH / sourceSize.height);
      overflow.x = sourceSize.width * scale - slotW;
      overflow.y = sourceSize.height * scale - slotH;
    }
    dragRef.current = {
      mode,
      handle,
      startX: event.clientX,
      startY: event.clientY,
      rect: slot.rect,
      focus: slot.focus ?? { x: 0.5, y: 0.5 },
      overflow,
      container,
      moved: false,
    };
    engine.beginTransaction();
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const onPointerMove = (event: ReactPointerEvent<HTMLElement>) => {
    const drag = dragRef.current;
    if (!drag) return;
    const dxPx = event.clientX - drag.startX;
    const dyPx = event.clientY - drag.startY;
    if (Math.hypot(dxPx, dyPx) > CLICK_SLOP_PX) drag.moved = true;
    if (!drag.moved) return;

    if (drag.mode === "crop") {
      // Dragging the content right reveals more of the source's left side,
      // so the focus moves opposite the pointer — and only where the cover
      // crop actually overflows the slot.
      const fx = drag.overflow.x > 1 ? clamp01(drag.focus.x - dxPx / drag.overflow.x) : drag.focus.x;
      const fy = drag.overflow.y > 1 ? clamp01(drag.focus.y - dyPx / drag.overflow.y) : drag.focus.y;
      save({ focus: { x: round3(fx), y: round3(fy) } });
      return;
    }

    const dx = dxPx / drag.container.width;
    const dy = dyPx / drag.container.height;
    const snapOff = event.metaKey || event.ctrlKey;
    const safe = safeAreaRect(engine.project.width, engine.project.height);
    const candidatesX = axisCandidates(layout, index, safe, "x");
    const candidatesY = axisCandidates(layout, index, safe, "y");
    const thresholdX = SNAP_PX / drag.container.width;
    const thresholdY = SNAP_PX / drag.container.height;
    const r = drag.rect;

    if (drag.mode === "move") {
      let x = clamp(r.x + dx, -0.45, 1.45 - r.w);
      let y = clamp(r.y + dy, -0.45, 1.45 - r.h);
      let guideX: number | null = null;
      let guideY: number | null = null;
      if (!snapOff) {
        const snapX = snapAxis([x, x + r.w / 2, x + r.w], candidatesX, thresholdX);
        x += snapX.delta;
        guideX = snapX.guide;
        const snapY = snapAxis([y, y + r.h / 2, y + r.h], candidatesY, thresholdY);
        y += snapY.delta;
        guideY = snapY.guide;
      }
      setGuides({ x: guideX, y: guideY, active: true });
      save({ rect: roundRect({ ...r, x, y }) });
      return;
    }

    const handle = drag.handle!;
    const corner = handle.length === 2;
    const locked = corner && !event.shiftKey;
    const dominantX = Math.abs(dxPx) >= Math.abs(dyPx);
    const right = r.x + r.w;
    const bottom = r.y + r.h;
    let w = handle.includes("e") ? r.w + dx : handle.includes("w") ? r.w - dx : r.w;
    let h = handle.includes("s") ? r.h + dy : handle.includes("n") ? r.h - dy : r.h;
    const ratio = r.w / r.h;
    if (locked) {
      if (dominantX) h = w / ratio;
      else w = h * ratio;
    }
    let guideX: number | null = null;
    let guideY: number | null = null;
    if (!snapOff) {
      // Snap the moving edges; with the aspect locked only the dominant axis
      // snaps, then the other re-derives so the ratio survives.
      if ((!locked || dominantX) && handle.includes("e")) {
        const snap = snapAxis([r.x + w], candidatesX, thresholdX);
        w += snap.delta;
        guideX = snap.guide;
      }
      if ((!locked || dominantX) && handle.includes("w")) {
        const snap = snapAxis([right - w], candidatesX, thresholdX);
        w -= snap.delta;
        guideX = snap.guide;
      }
      if ((!locked || !dominantX) && handle.includes("s")) {
        const snap = snapAxis([r.y + h], candidatesY, thresholdY);
        h += snap.delta;
        guideY = snap.guide;
      }
      if ((!locked || !dominantX) && handle.includes("n")) {
        const snap = snapAxis([bottom - h], candidatesY, thresholdY);
        h -= snap.delta;
        guideY = snap.guide;
      }
      if (locked) {
        if (dominantX) h = w / ratio;
        else w = h * ratio;
      }
    }
    w = clamp(w, MIN_SIZE, 3);
    h = clamp(h, MIN_SIZE, 3);
    const x = handle.includes("w") ? right - w : r.x;
    const y = handle.includes("n") ? bottom - h : r.y;
    setGuides({ x: guideX, y: guideY, active: true });
    save({ rect: roundRect({ x, y, w, h }) });
  };

  const end = (event: ReactPointerEvent<HTMLElement>) => {
    const drag = dragRef.current;
    if (!drag) return;
    dragRef.current = null;
    engine.endTransaction();
    setGuides(NO_GUIDES);
    event.currentTarget.releasePointerCapture(event.pointerId);
    // A press that never moved is a click: select the slot for the inspector.
    if (!drag.moved && drag.mode !== "resize") onSelect(index);
  };

  return (
    <div
      className={cn(
        "absolute border-2 bg-primary/10 hover:bg-primary/15",
        cropping
          ? "cursor-grab border-dashed border-primary active:cursor-grabbing"
          : selected
            ? "cursor-move border-primary"
            : "cursor-move border-primary/50",
      )}
      style={{
        left: `${slot.rect.x * 100}%`,
        top: `${slot.rect.y * 100}%`,
        width: `${slot.rect.w * 100}%`,
        height: `${slot.rect.h * 100}%`,
        // Mirror the render's rounding so radius edits read on the overlay too.
        borderRadius: `${slot.cornerRadius * 100}%`,
      }}
      onPointerDown={(event) => begin(cropping ? "crop" : "move", event)}
      onPointerMove={onPointerMove}
      onPointerUp={end}
      onPointerCancel={end}
      onDoubleClick={() => slot.fit === "cover" && onToggleCrop(index)}
    >
      <span className="absolute top-0.5 left-1.5 rounded-sm bg-overlay/60 px-1 text-2xs text-overlay-foreground/90 capitalize">
        {slot.source}
      </span>
      {selected &&
        !cropping &&
        HANDLES.map((handle) => (
          <span
            key={handle.id}
            data-handle={handle.id}
            className="absolute size-2.5 rounded-[2px] border border-overlay/40 bg-primary"
            style={{
              left: `${handle.x * 100}%`,
              top: `${handle.y * 100}%`,
              transform: "translate(-50%, -50%)",
              cursor: handle.cursor,
            }}
            onPointerDown={(event) => begin("resize", event, handle.id)}
            onPointerMove={onPointerMove}
            onPointerUp={end}
            onPointerCancel={end}
          />
        ))}
    </div>
  );
}

/** Mounted over the preview while a layout is being edited (multicam mode). */
export function LayoutSlotEditor() {
  const engine = useEditor();
  const { editingLayoutId, setEditingLayoutId, editingSlotIndex, setEditingSlotIndex } =
    useEditorUI();
  const [cropIndex, setCropIndex] = useState<number | null>(null);
  const [guides, setGuides] = useState<Guides>(NO_GUIDES);
  const layout = useEditorState((s) =>
    editingLayoutId ? s.project.layouts.find((l) => l.id === editingLayoutId) : undefined,
  );
  const selectedIds = useEditorState((s) => s.selection.elementIds);
  const lastLayoutRef = useRef<string | null>(null);

  // Entering a layout opens its topmost slot (usually the PiP) in the
  // inspector, so the panel is immediately useful.
  useEffect(() => {
    if (editingLayoutId === lastLayoutRef.current) return;
    lastLayoutRef.current = editingLayoutId;
    setCropIndex(null);
    if (editingLayoutId && layout) setEditingSlotIndex(layout.slots.length - 1);
  }, [editingLayoutId, layout, setEditingSlotIndex]);

  // Esc walks out one level (crop → slot selection → editor); arrows nudge
  // the selected slot by a pixel (Shift = 10). Capture phase so the global
  // playhead/selection hotkeys don't also fire.
  useEffect(() => {
    if (!layout) return;
    const onKeyDown = (event: KeyboardEvent) => {
      const target = event.target;
      if (
        target instanceof HTMLInputElement ||
        target instanceof HTMLTextAreaElement ||
        (target instanceof HTMLElement && target.isContentEditable)
      ) {
        return;
      }
      if (event.key === "Escape") {
        event.preventDefault();
        event.stopPropagation();
        if (cropIndex !== null) setCropIndex(null);
        else if (editingSlotIndex !== null) setEditingSlotIndex(null);
        else setEditingLayoutId(null);
        return;
      }
      if (!event.key.startsWith("Arrow") || editingSlotIndex === null) return;
      const slot = layout.slots[editingSlotIndex];
      if (!slot) return;
      event.preventDefault();
      event.stopPropagation();
      const px = event.shiftKey ? 10 : 1;
      const dx = event.key === "ArrowLeft" ? -px : event.key === "ArrowRight" ? px : 0;
      const dy = event.key === "ArrowUp" ? -px : event.key === "ArrowDown" ? px : 0;
      saveLayoutSlot(engine, layout, editingSlotIndex, {
        rect: roundRect({
          ...slot.rect,
          x: clamp(slot.rect.x + dx / engine.project.width, -0.45, 1.45 - slot.rect.w),
          y: clamp(slot.rect.y + dy / engine.project.height, -0.45, 1.45 - slot.rect.h),
        }),
      });
    };
    window.addEventListener("keydown", onKeyDown, true);
    return () => window.removeEventListener("keydown", onKeyDown, true);
  }, [engine, layout, cropIndex, editingSlotIndex, setEditingLayoutId, setEditingSlotIndex]);

  if (!layout) return null;

  // Crop panning needs the source's natural size; resolve it through the
  // multicam the bank targets (selected, else under playhead, else first).
  const target = findTargetMulticam(
    engine.project,
    selectedIds,
    engine.playback.state.currentTimeMs,
  );
  const sourceSize = (key: string) => {
    const source = target?.element.sources.find((s) => s.key === key);
    const asset = source ? engine.project.assets[source.assetId] : undefined;
    return asset?.width && asset?.height ? { width: asset.width, height: asset.height } : null;
  };

  const safe = safeAreaRect(engine.project.width, engine.project.height);

  return (
    <div
      data-mcut-slot-editor=""
      className="absolute inset-0 z-10"
      onPointerDown={(event) => {
        // Clicking empty canvas steps out of crop mode / slot selection.
        if (event.target !== event.currentTarget) return;
        setCropIndex(null);
        setEditingSlotIndex(null);
      }}
    >
      {guides.active && (
        <div
          className="pointer-events-none absolute border border-dashed border-(--snap-guide)/50"
          style={{
            left: `${safe.x * 100}%`,
            top: `${safe.y * 100}%`,
            width: `${safe.w * 100}%`,
            height: `${safe.h * 100}%`,
          }}
        />
      )}
      {guides.x !== null && (
        <div
          className="pointer-events-none absolute inset-y-0 w-px bg-(--snap-guide)"
          style={{ left: `${guides.x * 100}%` }}
        />
      )}
      {guides.y !== null && (
        <div
          className="pointer-events-none absolute inset-x-0 h-px bg-(--snap-guide)"
          style={{ top: `${guides.y * 100}%` }}
        />
      )}
      {layout.slots.map((slot, index) => (
        <SlotBox
          key={`${slot.source}-${index}`}
          layout={layout}
          slot={slot}
          index={index}
          selected={editingSlotIndex === index}
          cropping={cropIndex === index}
          sourceSize={sourceSize(slot.source)}
          onSelect={(i) => {
            setEditingSlotIndex(i);
            if (cropIndex !== null && cropIndex !== i) setCropIndex(null);
          }}
          onToggleCrop={(i) => {
            setEditingSlotIndex(i);
            setCropIndex((current) => (current === i ? null : i));
          }}
          setGuides={setGuides}
        />
      ))}
      <div className="absolute top-2 left-1/2 flex -translate-x-1/2 items-center gap-2 rounded-lg bg-overlay/65 px-2 py-1">
        <span className="text-2xs text-overlay-foreground/90">
          {cropIndex !== null
            ? "Drag inside the slot to pan its crop — Esc or double-click to finish"
            : `Editing “${layout.name}” — style it in the inspector`}
        </span>
        <Button
          size="xs"
          variant="secondary"
          onClick={() => {
            setCropIndex(null);
            setEditingSlotIndex(null);
            setEditingLayoutId(null);
          }}
        >
          Done
        </Button>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { useEditor, useEditorState, usePlayback } from "@mcut/react";
import {
  applyRunStyle,
  getRunStyleAt,
  resolveAnimatedElement,
  shiftRunsForEdit,
  type TextElement,
  type TextRun,
  type TextRunStylePatch,
} from "@mcut/timeline";
import { Button } from "@/components/ui/button";
import { useEditorUI } from "./editor-ui";

/**
 * Inline text editing ON the canvas (double-click a text element): a
 * contentEditable mirror of the element — same font, spacing, box, and
 * per-run styling — overlaid exactly on its frame while the compositor
 * skips drawing it (the editor IS the WYSIWYG render). A floating toolbar
 * over the selection styles ranges (bold / italic / color → rich-text
 * runs). The whole session is one engine transaction: every keystroke
 * dispatches live (history off), and closing the editor commits a single
 * undo entry.
 */

/** Editable DOM → plain text ('\n' from text nodes, <br>, and block starts). */
function readEditableText(root: HTMLElement): string {
  let out = "";
  const walk = (node: Node, isRoot: boolean) => {
    if (node.nodeType === Node.TEXT_NODE) {
      out += (node as Text).data;
      return;
    }
    if (node instanceof HTMLElement) {
      if (node.tagName === "BR") {
        out += "\n";
        return;
      }
      const isBlock = !isRoot && (node.tagName === "DIV" || node.tagName === "P");
      if (isBlock && out.length > 0 && !out.endsWith("\n")) out += "\n";
      for (const child of node.childNodes) walk(child, false);
    }
  };
  walk(root, true);
  return out;
}

/** Character length of a range's contents, measured like readEditableText. */
function rangeTextLength(range: Range): number {
  const probe = document.createElement("div");
  probe.appendChild(range.cloneContents());
  return readEditableText(probe).length;
}

/** Current selection as character offsets into the editable's text. */
function selectionOffsets(root: HTMLElement): { start: number; end: number } | null {
  const selection = window.getSelection();
  if (!selection || selection.rangeCount === 0) return null;
  const range = selection.getRangeAt(0);
  if (!root.contains(range.startContainer) || !root.contains(range.endContainer)) return null;
  const head = document.createRange();
  head.selectNodeContents(root);
  head.setEnd(range.startContainer, range.startOffset);
  const start = rangeTextLength(head);
  return { start, end: start + rangeTextLength(range) };
}

/** Restore a character-offset selection inside the editable. */
function setSelectionOffsets(root: HTMLElement, start: number, end: number): void {
  const locate = (target: number): { node: Node; offset: number } => {
    let remaining = target;
    const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT);
    let last: Text | null = null;
    for (let node = walker.nextNode() as Text | null; node; node = walker.nextNode() as Text | null) {
      last = node;
      if (remaining <= node.data.length) return { node, offset: remaining };
      remaining -= node.data.length;
    }
    return last ? { node: last, offset: last.data.length } : { node: root, offset: 0 };
  };
  const selection = window.getSelection();
  if (!selection) return;
  const range = document.createRange();
  const from = locate(start);
  const to = locate(end);
  range.setStart(from.node, from.offset);
  range.setEnd(to.node, to.offset);
  selection.removeAllRanges();
  selection.addRange(range);
}

/** Rebuild the editable's children as run-styled spans (newlines stay in text). */
function renderSpans(root: HTMLElement, text: string, runs: readonly TextRun[]): void {
  const edges = new Set<number>([0, text.length]);
  for (const run of runs) {
    if (run.start > 0 && run.start < text.length) edges.add(run.start);
    if (run.end > 0 && run.end < text.length) edges.add(run.end);
  }
  const sorted = [...edges].sort((a, b) => a - b);
  const children: Node[] = [];
  for (let i = 0; i < sorted.length - 1; i++) {
    const a = sorted[i]!;
    const b = sorted[i + 1]!;
    const style = getRunStyleAt(runs, a);
    const span = document.createElement("span");
    if (style.color) span.style.color = style.color;
    if (style.fontWeight !== undefined) span.style.fontWeight = String(style.fontWeight);
    if (style.fontStyle) span.style.fontStyle = style.fontStyle;
    span.textContent = text.slice(a, b);
    children.push(span);
  }
  root.replaceChildren(...children);
}

/** True when every character in [start, end) resolves bold / italic. */
function rangeHas(
  runs: readonly TextRun[],
  start: number,
  end: number,
  predicate: (style: ReturnType<typeof getRunStyleAt>) => boolean,
): boolean {
  if (end <= start) return predicate(getRunStyleAt(runs, start));
  for (let offset = start; offset < end; ) {
    const style = getRunStyleAt(runs, offset);
    if (!predicate(style)) return false;
    const run = runs.find((r) => offset >= r.start && offset < r.end);
    offset = run ? run.end : offset + 1;
  }
  return true;
}

export function TextEditOverlay() {
  const engine = useEditor();
  const { editingTextId, setEditingTextId } = useEditorUI();
  const element = useEditorState((s) => {
    if (!editingTextId) return null;
    for (const track of s.project.tracks) {
      const found = track.elements.find((e) => e.id === editingTextId);
      if (found && found.type === "text") return found;
    }
    return null;
  }) as TextElement | null;
  const projectSize = useEditorState((s) => ({ width: s.project.width, height: s.project.height }));
  const timeMs = usePlayback((s) => Math.round(s.currentTimeMs));

  const containerRef = useRef<HTMLDivElement | null>(null);
  const editableRef = useRef<HTMLDivElement | null>(null);
  const [scale, setScale] = useState(0);
  // The editing session's source of truth (DOM ↔ model sync). Handlers
  // read/write the ref; `runs` mirrors into state for render (toolbar
  // active flags, color swatch) so render never touches the ref.
  const sessionRef = useRef<{ text: string; runs: TextRun[] } | null>(null);
  const [runs, setRuns] = useState<TextRun[]>([]);
  const [selection, setSelection] = useState<{
    start: number;
    end: number;
    x: number;
    y: number;
  } | null>(null);

  // Track the container's px scale (project px → screen px).
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const update = () =>
      setScale(container.clientWidth > 0 ? container.clientWidth / projectSize.width : 0);
    update();
    const observer = new ResizeObserver(update);
    observer.observe(container);
    return () => observer.disconnect();
  }, [projectSize.width, editingTextId]);

  // Session lifecycle: one transaction per editing session; mount renders
  // the runs as spans and selects everything (Figma's double-click).
  useEffect(() => {
    if (!editingTextId) return;
    const current = engine.project;
    let original: TextElement | null = null;
    for (const track of current.tracks) {
      const found = track.elements.find((e) => e.id === editingTextId);
      if (found?.type === "text") original = found;
    }
    if (!original) return;
    sessionRef.current = { text: original.text, runs: [...(original.runs ?? [])] };
    setRuns(sessionRef.current.runs);
    engine.beginTransaction();
    const editable = editableRef.current;
    if (editable) {
      renderSpans(editable, original.text, original.runs ?? []);
      editable.focus();
      setSelectionOffsets(editable, 0, original.text.length);
    }
    return () => {
      sessionRef.current = null;
      engine.endTransaction();
    };
  }, [editingTextId, engine]);

  // Selection → toolbar position (container-relative).
  useEffect(() => {
    if (!editingTextId) return;
    const onSelectionChange = () => {
      const editable = editableRef.current;
      const container = containerRef.current;
      if (!editable || !container) return;
      const offsets = selectionOffsets(editable);
      const sel = window.getSelection();
      if (!offsets || !sel || sel.rangeCount === 0) {
        setSelection(null);
        return;
      }
      const rect = sel.getRangeAt(0).getBoundingClientRect();
      const host = container.getBoundingClientRect();
      const anchor = rect.width > 0 || rect.height > 0 ? rect : editable.getBoundingClientRect();
      setSelection({
        ...offsets,
        x: anchor.left + anchor.width / 2 - host.left,
        y: anchor.top - host.top,
      });
    };
    document.addEventListener("selectionchange", onSelectionChange);
    return () => document.removeEventListener("selectionchange", onSelectionChange);
  }, [editingTextId]);

  if (!editingTextId || !element || scale < 0) return null;

  const dispatchLive = (patch: Record<string, unknown>) => {
    try {
      engine.dispatch(
        { type: "updateElement", elementId: element.id, patch },
        { history: false },
      );
    } catch {
      // Element vanished mid-edit.
    }
  };

  const commit = () => {
    const session = sessionRef.current;
    if (session && session.text.trim() === "") {
      // Empty text exits as a delete (the transaction collapses it all).
      try {
        engine.dispatch({ type: "removeElement", elementId: element.id });
      } catch {
        // Already gone.
      }
    }
    setEditingTextId(null); // unmount effect ends the transaction
    setSelection(null);
  };

  const onInput = () => {
    const editable = editableRef.current;
    const session = sessionRef.current;
    if (!editable || !session) return;
    const newText = readEditableText(editable);
    session.runs = shiftRunsForEdit(session.runs, session.text, newText);
    session.text = newText;
    setRuns(session.runs);
    dispatchLive({ text: newText, runs: session.runs.length > 0 ? session.runs : undefined });
  };

  const applyToSelection = (patch: TextRunStylePatch) => {
    const editable = editableRef.current;
    const session = sessionRef.current;
    if (!editable || !session || !selection || selection.end <= selection.start) return;
    session.runs = applyRunStyle(
      session.runs,
      selection.start,
      selection.end,
      patch,
      session.text.length,
    );
    setRuns(session.runs);
    renderSpans(editable, session.text, session.runs);
    setSelectionOffsets(editable, selection.start, selection.end);
    editable.focus();
    dispatchLive({ runs: session.runs.length > 0 ? session.runs : undefined });
  };

  const baseBold = element.style.fontWeight >= 600;
  const baseItalic = element.style.fontStyle === "italic";
  const selBold =
    selection !== null &&
    rangeHas(runs, selection.start, selection.end, (s) => (s.fontWeight ?? element.style.fontWeight) >= 600);
  const selItalic =
    selection !== null &&
    rangeHas(
      runs,
      selection.start,
      selection.end,
      (s) => (s.fontStyle ?? element.style.fontStyle ?? "normal") === "italic",
    );

  // WYSIWYG placement: the element's resolved frame, in container px.
  const resolved = resolveAnimatedElement(element, timeMs);
  const style = resolved.style;
  const scaleX = Math.abs(resolved.transform.scaleX) * scale;
  const scaleY = Math.abs(resolved.transform.scaleY) * scale;
  const fontPx = style.fontSize * scaleY;
  const padPx = style.backgroundColor ? style.fontSize * 0.25 * scaleY : 0;
  const centerX = (projectSize.width / 2 + resolved.transform.x) * scale;
  const centerY = (projectSize.height / 2 + resolved.transform.y) * scale;
  // Box width drives wrapping; measure-derived width keeps free text stable.
  const boxWidthPx = element.box ? element.box.width * scaleX : null;

  return (
    <div ref={containerRef} className="absolute inset-0 z-20">
      {/* Click-away backdrop: commits (Figma semantics). */}
      <div className="absolute inset-0" onPointerDown={commit} />
      <div
        ref={editableRef}
        contentEditable
        suppressContentEditableWarning
        role="textbox"
        aria-multiline="true"
        data-mcut-text-editor=""
        spellCheck={false}
        className="absolute outline-2 outline-dashed outline-primary/70"
        style={{
          left: centerX,
          top: centerY,
          transform: `translate(-50%, -50%)${
            resolved.transform.rotation ? ` rotate(${resolved.transform.rotation}deg)` : ""
          }`,
          width: boxWidthPx ? `${boxWidthPx}px` : "max-content",
          minWidth: fontPx,
          whiteSpace: boxWidthPx ? "pre-wrap" : "pre",
          overflowWrap: boxWidthPx ? "break-word" : undefined,
          fontFamily: style.fontFamily,
          fontWeight: style.fontWeight,
          fontStyle: style.fontStyle,
          fontSize: `${fontPx}px`,
          lineHeight: style.lineHeight ?? 1.25,
          letterSpacing: `${(style.letterSpacing ?? 0) * scaleY}px`,
          textAlign: style.align,
          textTransform: style.textTransform === "none" ? undefined : style.textTransform,
          color: style.color,
          caretColor: style.color,
          backgroundColor: style.backgroundColor || undefined,
          padding: padPx ? `${padPx}px` : undefined,
          borderRadius: style.backgroundColor ? `${style.fontSize * 0.15 * scaleY}px` : undefined,
          WebkitTextStroke:
            style.stroke && style.stroke.width > 0
              ? `${style.stroke.width * scaleY}px ${style.stroke.color}`
              : undefined,
          textShadow: style.shadow
            ? `${style.shadow.offsetX * scaleY}px ${style.shadow.offsetY * scaleY}px ${
                style.shadow.blur * scaleY
              }px ${style.shadow.color}`
            : undefined,
        }}
        onInput={onInput}
        onKeyDown={(event) => {
          event.stopPropagation();
          if (event.key === "Escape") {
            event.preventDefault();
            commit();
            return;
          }
          if (event.key === "Enter" && !event.shiftKey && !event.metaKey) {
            // Plain text newline (keeps the DOM to text nodes + spans).
            event.preventDefault();
            document.execCommand("insertText", false, "\n");
          }
          if ((event.metaKey || event.ctrlKey) && event.key.toLowerCase() === "b") {
            event.preventDefault();
            applyToSelection({ fontWeight: selBold ? (baseBold ? 400 : null) : 700 });
          }
          if ((event.metaKey || event.ctrlKey) && event.key.toLowerCase() === "i") {
            event.preventDefault();
            applyToSelection({ fontStyle: selItalic ? (baseItalic ? "normal" : null) : "italic" });
          }
        }}
        onPointerDown={(event) => event.stopPropagation()}
      />
      {selection && selection.end > selection.start && (
        <div
          data-mcut-text-toolbar=""
          className="absolute z-30 flex -translate-x-1/2 -translate-y-full items-center gap-0.5 rounded-md bg-overlay/85 p-0.5 shadow-md backdrop-blur"
          style={{ left: selection.x, top: Math.max(28, selection.y) - 6 }}
          onPointerDown={(event) => {
            // Keep the editable's selection alive through toolbar clicks.
            event.preventDefault();
            event.stopPropagation();
          }}
        >
          <Button
            variant={selBold ? "secondary" : "ghost"}
            size="icon-xs"
            title="Bold (⌘B)"
            onClick={() => applyToSelection({ fontWeight: selBold ? (baseBold ? 400 : null) : 700 })}
          >
            <span className="text-xs font-bold">B</span>
          </Button>
          <Button
            variant={selItalic ? "secondary" : "ghost"}
            size="icon-xs"
            title="Italic (⌘I)"
            onClick={() =>
              applyToSelection({ fontStyle: selItalic ? (baseItalic ? "normal" : null) : "italic" })
            }
          >
            <span className="font-serif text-xs italic">I</span>
          </Button>
          <input
            type="color"
            title="Text color for the selection"
            className="size-5 cursor-pointer appearance-none rounded-sm border-0 bg-transparent p-0.5"
            value={
              /^#[0-9a-fA-F]{6}$/.test(getRunStyleAt(runs, selection.start).color ?? "")
                ? getRunStyleAt(runs, selection.start).color!
                : "#ffffff"
            }
            onChange={(event) => applyToSelection({ color: event.target.value })}
          />
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { toast } from "sonner";
import { DownloadIcon, ImageIcon } from "@/lib/hugeicons";
import { renderFrame } from "@mcut/compositor";
import { createAssetFromFile } from "@mcut/media";
import { useEditorContext, useEditorState } from "@mcut/react";
import {
  captureThumbnailTemplate,
  findThumbnailTrack,
  frameToMs,
  THUMBNAIL_TEMPLATES,
  thumbnailDurationMs,
  type ThumbnailTemplate,
} from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { PanelSectionLabel } from "./editor-primitives";
import { ensureFontLoaded, ensureProjectFontsLoaded } from "./font-library";
import { removeTemplate, saveTemplate, useTemplates } from "./template-store";
import { useEditorUI } from "./editor-ui";

/**
 * The thumbnail (cover) panel: compose the first five frames of the video.
 * CapCut's cover is metadata that vanishes on export; here the cover is real
 * elements on a locked "Thumbnail" track — baked into the export by
 * construction — with explicit PNG export as the sidecar option.
 */

export function ThumbnailPanel({ className }: { className?: string }) {
  const { engine, pool } = useEditorContext();
  const { setThumbnailSlots } = useEditorUI();
  const project = useEditorState((s) => s.project);
  const userTemplates = useTemplates<ThumbnailTemplate>("thumbnail");
  const [draftTexts, setDraftTexts] = useState<Record<string, string>>({});
  const [selected, setSelected] = useState<string>(THUMBNAIL_TEMPLATES[0]!.name);

  const all: Array<{ template: ThumbnailTemplate; templateId?: string }> = [
    ...THUMBNAIL_TEMPLATES.map((template) => ({ template })),
    ...userTemplates.map((t) => ({ template: t.payload, templateId: t.id })),
  ];
  const current = all.find((t) => t.template.name === selected) ?? all[0]!;

  // Publish the template's slots so the canvas shows drop targets mid-drag.
  useEffect(() => {
    const slots = current.template.items
      .filter((item): item is Extract<ThumbnailTemplate["items"][number], { kind: "slot" }> => item.kind === "slot")
      .map((item) => ({ rect: item.rect, label: item.label }));
    setThumbnailSlots(slots.length > 0 ? slots : null);
    return () => setThumbnailSlots(null);
  }, [current.template, setThumbnailSlots]);

  const textItems = current.template.items.filter(
    (item): item is Extract<ThumbnailTemplate["items"][number], { kind: "text" }> =>
      item.kind === "text",
  );

  const apply = () => {
    const template: ThumbnailTemplate = {
      ...current.template,
      items: current.template.items.map((item, i) =>
        item.kind === "text" && draftTexts[`${i}`] !== undefined
          ? { ...item, text: draftTexts[`${i}`]! }
          : item,
      ),
    };
    try {
      engine.dispatch({ type: "applyThumbnail", template });
      engine.seek(0);
      // The preview redraws every frame, so faces pop in as they load.
      for (const item of template.items) {
        if (item.kind === "text") {
          void ensureFontLoaded(item.style.fontFamily, item.style.fontWeight, item.style.fontStyle === "italic");
        }
      }
      toast.success("Cover applied to the first 5 frames — edit it on the canvas");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Could not apply the template");
    }
  };

  const grabFrame = async () => {
    try {
      const canvas = document.createElement("canvas");
      canvas.width = project.width;
      canvas.height = project.height;
      const ctx = canvas.getContext("2d")!;
      await ensureProjectFontsLoaded(project);
      renderFrame(ctx, project, engine.playback.state.currentTimeMs, { source: pool });
      const blob = await new Promise<Blob | null>((resolve) => canvas.toBlob(resolve, "image/png"));
      if (!blob) throw new Error("Could not capture the frame");
      const file = new File([blob], "cover-frame.png", { type: "image/png" });
      const asset = await createAssetFromFile(file);
      engine.transact(() => {
        engine.dispatch({ type: "addAsset", asset });
        let track = findThumbnailTrack(engine.project);
        if (!track) {
          engine.dispatch({ type: "addTrack", name: "Thumbnail" });
          track = findThumbnailTrack(engine.project)!;
          engine.dispatch({ type: "setTrackFlags", trackId: track.id, locked: true });
        }
        engine.dispatch({
          type: "addElement",
          trackId: track.id,
          element: {
            type: "image",
            assetId: asset.id,
            startMs: 0,
            durationMs: thumbnailDurationMs(engine.project.fps),
          },
        });
      });
      engine.seek(0);
      toast.success("Playhead frame added as the cover backdrop");
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Frame grab failed");
    }
  };

  const exportPng = async () => {
    try {
      const canvas = document.createElement("canvas");
      canvas.width = project.width;
      canvas.height = project.height;
      const ctx = canvas.getContext("2d")!;
      // Canvas text silently falls back when a face isn't loaded yet — gate
      // the export render on every font the project references.
      await ensureProjectFontsLoaded(project);
      renderFrame(ctx, project, frameToMs(0, project.fps) + 1, { source: pool });
      const blob = await new Promise<Blob | null>((resolve) => canvas.toBlob(resolve, "image/png"));
      if (!blob) throw new Error("Render failed");
      const url = URL.createObjectURL(blob);
      const anchor = document.createElement("a");
      anchor.href = url;
      anchor.download = `${project.name}-cover.png`;
      anchor.click();
      URL.revokeObjectURL(url);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Export failed");
    }
  };

  const saveAsTemplate = () => {
    const name = window.prompt("Name this cover template", "My cover");
    if (!name) return;
    const captured = captureThumbnailTemplate(engine.project, name);
    if (!captured) {
      toast.error("Apply a cover first — then save your edited version as a template.");
      return;
    }
    saveTemplate("thumbnail", name, captured);
    toast.success(`Saved "${name}" for your next video`);
  };

  return (
    <div className={cn("flex flex-col gap-3 p-3", className)}>
      <div className="flex flex-col gap-1.5">
        <PanelSectionLabel>Templates</PanelSectionLabel>
        <div className="grid grid-cols-2 gap-1.5">
          {all.map(({ template, templateId }) => (
            <button
              key={templateId ?? template.name}
              type="button"
              className={cn(
                "group/tpl relative flex aspect-video flex-col justify-end rounded-lg bg-foreground/[0.06] p-1.5 text-left transition-shadow",
                template.name === selected
                  ? "ring-2 ring-primary"
                  : "hover:ring-1 hover:ring-foreground/25",
              )}
              onClick={() => {
                setSelected(template.name);
                setDraftTexts({});
              }}
            >
              <TemplatePreview template={template} />
              <span className="relative z-10 truncate text-2xs">{template.name}</span>
              {templateId && (
                <span
                  role="button"
                  tabIndex={-1}
                  className="absolute top-0.5 right-1 z-10 hidden text-2xs text-muted-foreground group-hover/tpl:block hover:text-destructive"
                  title="Delete template"
                  onClick={(event) => {
                    event.stopPropagation();
                    removeTemplate(templateId);
                  }}
                >
                  ✕
                </span>
              )}
            </button>
          ))}
        </div>
      </div>

      {textItems.length > 0 && (
        <div className="flex flex-col gap-1.5">
          <PanelSectionLabel>Text</PanelSectionLabel>
          {current.template.items.map((item, i) =>
            item.kind === "text" ? (
              <Input
                key={i}
                value={draftTexts[`${i}`] ?? item.text}
                placeholder={item.role}
                className="h-7 text-xs"
                onChange={(event) =>
                  setDraftTexts((prev) => ({ ...prev, [`${i}`]: event.target.value }))
                }
              />
            ) : null,
          )}
        </div>
      )}

      <Button size="sm" onClick={apply}>
        Apply to first 5 frames
      </Button>
      <div className="grid grid-cols-2 gap-1.5">
        <Button variant="outline" size="xs" onClick={grabFrame} title="Use the frame under the playhead as the cover backdrop">
          <ImageIcon /> Use frame
        </Button>
        <Button variant="outline" size="xs" onClick={exportPng} title="Export the cover as a PNG (e.g. for YouTube's thumbnail upload)">
          <DownloadIcon /> PNG
        </Button>
      </div>
      <Button variant="ghost" size="xs" onClick={saveAsTemplate}>
        Save current cover as template
      </Button>
      <p className="text-2xs leading-relaxed text-muted-foreground">
        The cover lives on the locked “Thumbnail” track over the first 5 frames, so it survives
        export. Safe-area guides show on the canvas while in Thumbnail mode.
      </p>
    </div>
  );
}

/** Schematic mini-preview: text items as bars, slots as dashed boxes. */
function TemplatePreview({ template }: { template: ThumbnailTemplate }) {
  return (
