}

function SlotTarget({
  rect,
  label,
}: {
  rect: { x: number; y: number; w: number; h: number };
  label: string;
}) {
  const { isOver, setNodeRef } = useDroppable({
    id: `thumb-slot-${label}-${rect.x}-${rect.y}`,
