    <div
      ref={setNodeRef}
      className={cn(
        "absolute flex items-center justify-center rounded-md border-2 border-dashed transition-colors",
        isOver ? "border-primary bg-primary/20" : "border-primary/50 bg-primary/5",
      )}
      style={{
        left: `${rect.x * 100}%`,
        top: `${rect.y * 100}%`,
        width: `${rect.w * 100}%`,
        height: `${rect.h * 100}%`,
      }}
    >
      <span className="rounded-sm bg-overlay/60 px-1.5 py-0.5 text-2xs text-overlay-foreground/90">
        {isOver ? "Drop to fill" : `Drop ${label.toLowerCase()} here`}
      </span>
