/**
 * The webapp half of the element-type registry: how a type LOOKS in the
 * editor chrome (timeline clip color, track icon). Custom element types
 * register here after registerTimelineElementType (engine) and
 * registerElementRenderer (compositor); anything unregistered falls back to
 * a neutral style so unknown types are visible, not invisible.
 */

export interface ElementUI {
  /** Timeline clip chip classes (bg + text color, alpha baked in). */
  clipClassName: string;
  /** Track-header icon for tracks led by this type. */
  icon: typeof FilmIcon;
}

const FALLBACK: ElementUI = {
  clipClassName: "bg-(--clip-fallback,oklch(35%_0.02_270/90%)) text-overlay-foreground",
  icon: LayersIcon,
};

const registry = new Map<string, ElementUI>();

export function registerElementUI(type: string, ui: ElementUI): void {
  registry.set(type, ui);
}

export function getElementUI(type: string): ElementUI {
  return registry.get(type) ?? FALLBACK;
}

// Built-ins, on the project's clip-color tokens (globals.css).
registerElementUI("video", {
  clipClassName: "bg-(--clip-video) text-(--clip-video-foreground)",
  icon: FilmIcon,
});
registerElementUI("audio", {
  clipClassName: "bg-(--clip-audio) text-(--clip-audio-foreground)",
  icon: MusicIcon,
});
registerElementUI("image", {
  clipClassName: "bg-(--clip-image) text-(--clip-image-foreground)",
  icon: ImageIcon,
});
registerElementUI("text", {
  clipClassName: "bg-(--clip-text) text-(--clip-text-foreground)",
  icon: TypeIcon,
});
registerElementUI("caption", {
  clipClassName: "bg-(--clip-caption) text-(--clip-caption-foreground)",
  icon: CaptionsIcon,
});
registerElementUI("multicam", {
  clipClassName: "bg-(--clip-multicam) text-(--clip-multicam-foreground)",
  icon: ClapperboardIcon,
});

import {
  getActiveAngleIndex,
  type EditorEngine,
  type MulticamElement,
  type Project,
} from "@mcut/timeline";

/**
 * Multicam UI helpers: which multicam the mode operates on, and the
 * playing-vs-paused switch semantics (Premiere parity — see the plan doc).
 */

export interface LocatedMulticam {
  element: MulticamElement;
  trackId: Project["tracks"][number]["id"];
}

/** The multicam the bank/hotkeys target: selected first, else under playhead, else first. */
export function findTargetMulticam(
  project: Project,
  selectedIds: readonly string[],
  playheadMs: number,
): LocatedMulticam | null {
  let underPlayhead: LocatedMulticam | null = null;
  let first: LocatedMulticam | null = null;
  for (const track of project.tracks) {
    for (const element of track.elements) {
      if (element.type !== "multicam") continue;
      const located = { element, trackId: track.id };
      if (selectedIds.includes(element.id)) return located;
      if (
        !underPlayhead &&
        playheadMs >= element.startMs &&
        playheadMs < element.startMs + element.durationMs
      ) {
        underPlayhead = located;
      }
      if (!first) first = located;
    }
  }
  return underPlayhead ?? first;
}

/**
 * The multicam switch gesture: while PLAYING a press cuts at the playhead
 * (you're performing the edit live); while PAUSED it corrects the layout of
 * the span under the playhead. This split is what makes multicam editing
 * fast — copy Premiere exactly.
 */
export function switchToLayout(
  engine: EditorEngine,
  element: MulticamElement,
  layoutId: string,
): void {
  const playheadMs = engine.playback.state.currentTimeMs;
  const localMs = Math.round(playheadMs - element.startMs);
  if (localMs < 0 || localMs >= element.durationMs) return;
  try {
    if (engine.playback.state.isPlaying && localMs > 0) {
      engine.dispatch({ type: "addAngleCut", elementId: element.id, atMs: localMs, layoutId });
    } else {
      const span = element.angles[getActiveAngleIndex(element.angles, localMs)];
      if (!span) return;
      engine.dispatch({
        type: "setAngleLayout",
        elementId: element.id,
        atMs: span.atMs,
        layoutId,
      });
    }
  } catch {
    // Cut collided with an existing one at the same ms: ignore.
  }
}

